const ST36 = "<p>The boiling points of four organic liquids of similar molar mass are compared. Boiling point reflects the strength of the forces between molecules: weak dispersion forces, stronger dipole-dipole forces, and the strongest, hydrogen bonding (which needs O-H or N-H).</p><table><caption>Boiling points</caption><thead><tr><th>Molecule</th><th>Molar mass (g/mol)</th><th>Boiling point (&deg;C)</th></tr></thead><tbody><tr><td>Butane (CH<sub>3</sub>CH<sub>2</sub>CH<sub>2</sub>CH<sub>3</sub>)</td><td>58</td><td>-0.5</td></tr><tr><td>Propanal (CH<sub>3</sub>CH<sub>2</sub>CHO)</td><td>58</td><td>49</td></tr><tr><td>Propan-1-ol (CH<sub>3</sub>CH<sub>2</sub>CH<sub>2</sub>OH)</td><td>60</td><td>97</td></tr><tr><td>Acetic acid (CH<sub>3</sub>COOH)</td><td>60</td><td>118</td></tr></tbody></table>";
const ST37 = "<p>Alkenes (C=C) undergo electrophilic addition. When an unsymmetrical reagent such as HBr adds to an unsymmetrical alkene, the hydrogen attaches to the double-bonded carbon that already has more hydrogens (Markovnikov's rule), because this forms the more stable carbocation intermediate. Carbocation stability increases tertiary > secondary > primary.</p><p>Consider propene, CH<sub>3</sub>-CH=CH<sub>2</sub>, reacting with HBr.</p>";
const ST38 = "<p>A trolley starts from rest and accelerates uniformly along a straight track. Its velocity was recorded against time.</p><table><caption>Velocity versus time</caption><thead><tr><th>Time (s)</th><th>0</th><th>2</th><th>4</th><th>6</th></tr></thead><tbody><tr><td>Velocity (m/s)</td><td>0</td><td>10</td><td>20</td><td>30</td></tr></tbody></table>";
const ST39 = "<p>For a block of mass 2 kg, the net force and motion obey Newton's second law, F = ma. Weight is mg with g = 10 m/s<sup>2</sup>. On a frictionless slope inclined at angle &theta;, the force pulling the block down the slope is mg sin&theta; (sin 30&deg; = 0.5).</p>";
const ST40 = "<p>A 12 V battery is connected to two resistors, of 4 ohm and 2 ohm. The table compares connecting them in series with connecting them in parallel. Recall V = IR and electrical power P = VI.</p><table><caption>Two resistor arrangements</caption><thead><tr><th>Arrangement</th><th>Total resistance</th></tr></thead><tbody><tr><td>Series (4 + 2)</td><td>6 ohm</td></tr><tr><td>Parallel (4 with 2)</td><td>1.33 ohm</td></tr></tbody></table>";
const ST41 = "<p>The activity of a radioactive sample was recorded over time.</p><table><caption>Radioactive decay</caption><thead><tr><th>Time (days)</th><th>0</th><th>5</th><th>10</th><th>15</th></tr></thead><tbody><tr><td>Activity (Bq)</td><td>800</td><td>400</td><td>200</td><td>100</td></tr></tbody></table>";
const ST42 = "<p>All waves obey v = f&lambda; (speed = frequency x wavelength). A string fixed at both ends has a fundamental (lowest) standing wave whose wavelength is twice the string length, 2L; the higher harmonics have frequencies that are whole-number multiples of the fundamental. The speed of sound in air is about 340 m/s.</p>";
const ST43 = "<p>For a thin converging lens, 1/f = 1/u + 1/v, where u is the object distance, v the image distance and f the focal length; the magnification is v/u. When light passes into a less dense medium it bends away from the normal, and beyond a critical angle it is totally internally reflected. A converging lens here has f = 10 cm.</p>";
const ST44 = "<p>Pressure in a liquid is P = &rho;gh (&rho; = density, g = 10 m/s<sup>2</sup>). A submerged or floating object feels an upthrust equal to the weight of fluid it displaces; it floats if its density is less than the fluid's. Water has &rho; = 1000 kg/m<sup>3</sup>.</p><table><caption>Gauge pressure in water</caption><thead><tr><th>Depth (m)</th><th>0</th><th>5</th><th>10</th></tr></thead><tbody><tr><td>Pressure (kPa)</td><td>0</td><td>50</td><td>100</td></tr></tbody></table>";
const ST45 = "<p>Useful energy relationships: kinetic energy KE = (1/2)mv<sup>2</sup>; gravitational potential energy PE = mgh (g = 10 m/s<sup>2</sup>); power P = work/time; efficiency = useful energy out / total energy in.</p>";
const ST46 = "<p>Momentum is p = mv and is conserved in any collision (total momentum before = total after). Impulse, the change in momentum, equals force x time (Ft). Kinetic energy is (1/2)mv<sup>2</sup>.</p>";
const ST47 = "<p>The table gives the composition of six foods per 100 g.</p><table><caption>Nutrient content per 100 g</caption><thead><tr><th>Food</th><th>Energy (kJ)</th><th>Protein (g)</th><th>Fat (g)</th><th>Carbohydrate (g)</th><th>Fibre (g)</th></tr></thead><tbody><tr><td>Rolled oats</td><td>1600</td><td>13</td><td>7</td><td>60</td><td>10</td></tr><tr><td>Almonds</td><td>2400</td><td>21</td><td>50</td><td>9</td><td>12</td></tr><tr><td>Chicken breast</td><td>700</td><td>31</td><td>4</td><td>0</td><td>0</td></tr><tr><td>White rice (cooked)</td><td>540</td><td>3</td><td>0</td><td>28</td><td>0</td></tr><tr><td>Broccoli</td><td>140</td><td>3</td><td>0</td><td>4</td><td>3</td></tr><tr><td>Olive oil</td><td>3700</td><td>0</td><td>100</td><td>0</td><td>0</td></tr></tbody></table>";
const ST48 = "<p>A patient weighing 70 kg is prescribed a drug at a dose of 2 mg per kg of body weight. The drug is supplied as a solution containing 10 mg per mL. The full dose is then to be given by infusion. Recall 1 km = 1000 m and 1 hour = 3600 s where needed.</p>";
const ST49 = "<p>Several scientific scales are logarithmic: each whole step changes the underlying quantity by a factor of ten. On the pH scale a fall of one unit is a ten-fold rise in [H<sup>+</sup>]. On the Richter scale each unit is a ten-fold rise in ground-motion amplitude. For sound, every 10 decibels (dB) is a ten-fold rise in intensity. (Use log10(2) = 0.30.)</p>";
const ST50 = "<p>For a sphere or any fixed shape scaled by a length r: surface area is proportional to r<sup>2</sup>, while volume is proportional to r<sup>3</sup>. The surface-area-to-volume ratio therefore scales as 1/r. Separately, a certain reaction rate is proportional to 1/&radic;M, where M is a particle's mass.</p>";

const GS3_QUESTIONS = [

  { id: "gs3-bio-001", subject: "biology", topic: "metabolism", stimulusId: "gs3-b1", stimulus: { kind: "html", content: ST1, attribution: "Original" }, stem: "Reading down each column, the maximum rate the enzyme can approach (its V-max) is changed by:", format: "single_best", options: ["Y only", "X only", "both X and Y", "neither X nor Y"], answer: 0, explanation: "Control and +X both keep climbing toward about 100 (89 at [S]=32), so X leaves Vmax unchanged. The +Y column flattens near 44, a much lower ceiling, so only Y lowers Vmax.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-002", subject: "biology", topic: "metabolism", stimulusId: "gs3-b1", stimulus: { kind: "html", content: ST1, attribution: "Original" }, stem: "The Michaelis constant K-m equals the substrate concentration giving half of V-max. For the Control, K-m is closest to:", format: "single_best", options: ["4 mmol/L", "1 mmol/L", "8 mmol/L", "16 mmol/L"], answer: 0, explanation: "Control Vmax is about 100, so half is 50. The rate is 50 at [S] = 4 mmol/L, so Km is about 4.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-003", subject: "biology", topic: "metabolism", stimulusId: "gs3-b1", stimulus: { kind: "html", content: ST1, attribution: "Original" }, stem: "X reaches the same V-max as the control but needs more substrate to get there. X is therefore best described as:", format: "single_best", options: ["a non-competitive inhibitor", "an irreversible poison", "a competitive inhibitor", "an activator"], answer: 2, explanation: "Unchanged Vmax but a higher apparent Km (more substrate needed for half-maximal rate) is the signature of a competitive inhibitor, which can be out-competed by substrate.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-004", subject: "biology", topic: "metabolism", stimulusId: "gs3-b1", stimulus: { kind: "html", content: ST1, attribution: "Original" }, stem: "Doubling the substrate concentration would most nearly restore the control rate in the presence of:", format: "single_best", options: ["Y, because its effect is relieved by excess substrate", "X, because its effect is relieved by excess substrate", "both equally", "neither, as both are irreversible"], answer: 1, explanation: "Only the competitive inhibitor X can be overcome by adding substrate; the non-competitive inhibitor Y lowers Vmax no matter how much substrate is present.", difficulty: "medium", source: "original" },

  { id: "gs3-bio-005", subject: "biology", topic: "genetics", stimulusId: "gs3-b2", stimulus: { kind: "html", content: ST2, attribution: "Original" }, stem: "The frequency of the recessive allele s is:", format: "single_best", options: ["0.09", "0.42", "0.51", "0.30"], answer: 3, explanation: "Count alleles: s = (2 x 90 + 420) / 2000 = 600/2000 = 0.30.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-006", subject: "biology", topic: "genetics", stimulusId: "gs3-b2", stimulus: { kind: "html", content: ST2, attribution: "Original" }, stem: "Comparing the observed counts with the Hardy-Weinberg prediction, the population is:", format: "single_best", options: ["far from equilibrium, with too many heterozygotes", "far from equilibrium, with too few heterozygotes", "essentially at Hardy-Weinberg equilibrium", "impossible to assess from these data"], answer: 2, explanation: "With p = 0.7, q = 0.3, expected counts are p^2 = 490 (SS), 2pq = 420 (Ss), q^2 = 90 (ss), which match the observed counts exactly.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-007", subject: "biology", topic: "genetics", stimulusId: "gs3-b2", stimulus: { kind: "html", content: ST2, attribution: "Original" }, stem: "What fraction of the dominant-phenotype (S-showing) beetles are heterozygous carriers?", format: "single_best", options: ["about 30%", "about 42%", "about 88%", "about 46%"], answer: 3, explanation: "S-showing beetles are SS + Ss = 490 + 420 = 910. Carriers are 420 of these: 420/910 = 0.46, about 46%.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-008", subject: "biology", topic: "genetics", stimulusId: "gs3-b2", stimulus: { kind: "html", content: ST2, attribution: "Original" }, stem: "Immediately after the cull, the frequency of the s allele among the survivors becomes closest to:", format: "single_best", options: ["0.30", "0.42", "0.15", "0.23"], answer: 3, explanation: "Survivors carry 2 x 490 + 2 x 420 = 1820 alleles, of which s = 420 (all in heterozygotes). 420/1820 = 0.23.", addedInfo: "A predator now removes every ss beetle before it can breed, leaving only the 490 SS and 420 Ss to reproduce.", difficulty: "hard", source: "original" },

  { id: "gs3-bio-009", subject: "biology", topic: "physiology", stimulusId: "gs3-b3", stimulus: { kind: "html", content: ST3, attribution: "Original" }, stem: "At a tissue pO2 of 40 mmHg, how many extra percentage points of oxygen does haemoglobin release in exercising muscle compared with resting tissue?", format: "single_best", options: ["8", "18", "33", "57"], answer: 1, explanation: "At 40 mmHg the saturation is 75% at rest and 57% when exercising, so 75 - 57 = 18 percentage points more oxygen are unloaded.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-010", subject: "biology", topic: "physiology", stimulusId: "gs3-b3", stimulus: { kind: "html", content: ST3, attribution: "Original" }, stem: "The shift between the two curves (the Bohr effect) is most directly triggered in active muscle by:", format: "single_best", options: ["a rise in pH and a fall in CO2", "a fall in temperature", "a rise in blood oxygen", "a fall in pH and a rise in CO2"], answer: 3, explanation: "Active muscle produces CO2 and acid, lowering pH. This rightward shift lowers haemoglobin's oxygen affinity so more oxygen is delivered where it is needed.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-011", subject: "biology", topic: "physiology", stimulusId: "gs3-b3", stimulus: { kind: "html", content: ST3, attribution: "Original" }, stem: "In the lungs the pO2 is about 100 mmHg. The table shows that the curve's S-shape ensures loading in the lungs is:", format: "single_best", options: ["nearly complete and barely affected by the pH shift", "severely impaired by exercise", "lower than the loading in the tissues", "linearly proportional to pO2"], answer: 0, explanation: "At 100 mmHg saturation is 98% (rest) and still 95% (exercise): the curve plateaus, so the lungs load haemoglobin almost fully regardless of the Bohr shift.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-012", subject: "biology", topic: "physiology", stimulusId: "gs3-b3", stimulus: { kind: "html", content: ST3, attribution: "Original" }, stem: "On the same axes, the fetal-haemoglobin curve would lie:", format: "single_best", options: ["to the right of (below) the adult resting curve", "to the left of (above) the adult resting curve", "exactly on the exercising curve", "as a horizontal straight line"], answer: 1, explanation: "Higher affinity means higher saturation at any given pO2, shifting the curve up and to the left, which lets the fetus draw oxygen from the mother across the placenta.", addedInfo: "Fetal haemoglobin binds oxygen more tightly than adult haemoglobin at every pO2.", difficulty: "hard", source: "original" },

  { id: "gs3-bio-013", subject: "biology", topic: "metabolism", stimulusId: "gs3-b4", stimulus: { kind: "html", content: ST4, attribution: "Original" }, stem: "Using the stated yields (NADH = 3 ATP, FADH2 = 2 ATP), the total ATP per glucose is:", format: "single_best", options: ["30", "24", "12", "38"], answer: 3, explanation: "Direct ATP = 4. NADH total = 10, giving 30. FADH2 = 2, giving 4. Total = 4 + 30 + 4 = 38.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-014", subject: "biology", topic: "metabolism", stimulusId: "gs3-b4", stimulus: { kind: "html", content: ST4, attribution: "Original" }, stem: "What fraction of the total ATP is produced by the electron transport chain (i.e. from NADH and FADH2) rather than directly?", format: "single_best", options: ["about 89%", "about 50%", "about 11%", "about 100%"], answer: 0, explanation: "Chain-derived ATP = 30 + 4 = 34 out of 38, which is 34/38 = 0.89, about 89%.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-015", subject: "biology", topic: "metabolism", stimulusId: "gs3-b4", stimulus: { kind: "html", content: ST4, attribution: "Original" }, stem: "With cyanide present but glycolysis still able to run by fermentation, the ATP yield per glucose falls closest to:", format: "single_best", options: ["38", "34", "0", "2"], answer: 3, explanation: "Blocking the chain removes the 34 ATP it makes and stalls the Krebs cycle. Only glycolysis continues (regenerating NAD+ by fermentation), giving its net 2 ATP.", addedInfo: "Cyanide blocks the final step of the electron transport chain, so no NADH or FADH2 can be reoxidised and the chain stops.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-016", subject: "biology", topic: "metabolism", stimulusId: "gs3-b4", stimulus: { kind: "html", content: ST4, attribution: "Original" }, stem: "Which observation best explains why the electron transport chain stops without oxygen?", format: "single_best", options: ["Oxygen is the final acceptor of the electrons, so without it the chain backs up", "Oxygen is a direct reactant of glycolysis", "Oxygen donates electrons to NAD+", "Oxygen is needed to make pyruvate"], answer: 0, explanation: "The chain passes electrons to oxygen at the end. With no oxygen to accept them, electrons cannot flow, NADH cannot be reoxidised, and the chain halts.", difficulty: "medium", source: "original" },

  { id: "gs3-bio-017", subject: "biology", topic: "cells_membranes", stimulusId: "gs3-b5", stimulus: { kind: "html", content: ST5, attribution: "Original" }, stem: "For Na+, both the concentration gradient and the membrane voltage:", format: "single_best", options: ["oppose each other, giving no net force", "drive Na+ inward", "drive Na+ outward", "act only on Cl-"], answer: 1, explanation: "Na+ is far more concentrated outside (so diffusion drives it in) and the inside is negative (so the electrical force also pulls the positive ion in). Both push Na+ inward.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-018", subject: "biology", topic: "cells_membranes", stimulusId: "gs3-b5", stimulus: { kind: "html", content: ST5, attribution: "Original" }, stem: "The Na+/K+ pump moves 3 Na+ out and 2 K+ in per cycle. Maintaining these gradients requires the pump to work because it moves each ion:", format: "single_best", options: ["down its concentration gradient", "without any energy", "only when the cell is dividing", "against its concentration gradient"], answer: 3, explanation: "The pump expels Na+ (already low inside) and imports K+ (already high inside), each against its concentration gradient, which is why it consumes ATP.", difficulty: "easy", source: "original" },
  { id: "gs3-bio-019", subject: "biology", topic: "cells_membranes", stimulusId: "gs3-b5", stimulus: { kind: "html", content: ST5, attribution: "Original" }, stem: "K+ is about 28 times more concentrated inside than outside, yet little K+ leaks out at rest. The best explanation is that:", format: "single_best", options: ["the negative interior voltage pulls the positive K+ back in, opposing its outward concentration gradient", "K+ cannot cross the membrane at all", "K+ is pumped out continuously", "the outside is also negative"], answer: 0, explanation: "K+ tends to diffuse out (high inside), but the negative interior attracts the positive ion inward. These opposing forces nearly balance, so net K+ movement is small.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-020", subject: "biology", topic: "cells_membranes", stimulusId: "gs3-b5", stimulus: { kind: "html", content: ST5, attribution: "Original" }, stem: "The cell will:", format: "single_best", options: ["lose water and shrink", "neither gain nor lose water", "gain water and swell", "pump salt outward to match"], answer: 2, explanation: "Water moves by osmosis from the dilute (hypotonic) outside toward the more concentrated interior, so the cell gains water and swells.", addedInfo: "The cell is now placed in a solution whose total solute concentration is far lower than the cell's interior.", difficulty: "medium", source: "original" },

  { id: "gs3-bio-021", subject: "biology", topic: "genetics", stimulusId: "gs3-b6", stimulus: { kind: "html", content: ST6, attribution: "Original" }, stem: "Two unaffected parents have an affected son. This immediately shows the allele is:", format: "single_best", options: ["dominant", "recessive", "found only in males", "newly mutated in the son"], answer: 1, explanation: "If neither parent shows the trait but a child does, the parents must each carry a hidden copy: the allele is recessive.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-022", subject: "biology", topic: "genetics", stimulusId: "gs3-b6", stimulus: { kind: "html", content: ST6, attribution: "Original" }, stem: "The affected son (II-1) is male while all daughters are unaffected. Combined with the rarity of the disorder, the most likely inheritance is:", format: "single_best", options: ["X-linked recessive", "Y-linked", "autosomal dominant", "mitochondrial"], answer: 0, explanation: "A recessive disorder appearing in a son of an unaffected carrier mother, with daughters unaffected, fits X-linked recessive: the mother carries one affected X and passes it to the son, who has no second X to mask it.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-023", subject: "biology", topic: "genetics", stimulusId: "gs3-b6", stimulus: { kind: "html", content: ST6, attribution: "Original" }, stem: "If the condition is X-linked recessive, the probability that the unaffected mother (I-2) is a carrier is:", format: "single_best", options: ["1 (certain)", "0", "1/4", "1/2"], answer: 0, explanation: "She has an affected son, who received his single X from her. She must therefore carry the allele on one of her X chromosomes: the probability is 1.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-024", subject: "biology", topic: "genetics", stimulusId: "gs3-b6", stimulus: { kind: "html", content: ST6, attribution: "Original" }, stem: "For any future son of this couple, the probability of being affected (X-linked recessive) is:", format: "single_best", options: ["1/2", "1/4", "1", "0"], answer: 0, explanation: "The carrier mother passes either her normal or her affected X with equal chance; the father gives a Y. So a son has a 1/2 chance of inheriting the affected X and being affected.", difficulty: "hard", source: "original" },

  { id: "gs3-bio-025", subject: "biology", topic: "physiology", stimulusId: "gs3-b7", stimulus: { kind: "html", content: ST7, attribution: "Original" }, stem: "Comparing axons P and Q (both unmyelinated), the data show velocity rises with:", format: "single_best", options: ["smaller diameter", "lower temperature", "larger diameter", "shorter length"], answer: 2, explanation: "P (1 micrometre) conducts at 1 m/s while Q (4 micrometre) conducts at 4 m/s, so velocity increases with diameter.", difficulty: "easy", source: "original" },
  { id: "gs3-bio-026", subject: "biology", topic: "physiology", stimulusId: "gs3-b7", stimulus: { kind: "html", content: ST7, attribution: "Original" }, stem: "Axons Q and R have the same diameter (4 micrometre). The jump from 4 to 25 m/s is due to:", format: "single_best", options: ["myelination", "a larger diameter", "a higher stimulus strength", "a lower threshold"], answer: 0, explanation: "Q and R differ only in myelination, so the sheath (letting the impulse jump between gaps) accounts for the roughly six-fold speed increase.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-027", subject: "biology", topic: "physiology", stimulusId: "gs3-b7", stimulus: { kind: "html", content: ST7, attribution: "Original" }, stem: "Based on the table, destroying the myelin of axon S (currently 60 m/s) would be expected to:", format: "single_best", options: ["increase its conduction velocity", "leave its velocity unchanged", "reverse the direction of conduction", "greatly reduce its conduction velocity"], answer: 3, explanation: "Myelination is what raises velocity dramatically (compare Q and R). Removing it would drop S toward the slow unmyelinated range, impairing signalling.", addedInfo: "In multiple sclerosis the myelin sheath is progressively destroyed.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-028", subject: "biology", topic: "physiology", stimulusId: "gs3-b7", stimulus: { kind: "html", content: ST7, attribution: "Original" }, stem: "A 1.2 m motor axon like S (60 m/s) carries an impulse from spinal cord to foot in about:", format: "single_best", options: ["0.2 s", "2 s", "0.02 s", "20 s"], answer: 2, explanation: "Time = distance / speed = 1.2 / 60 = 0.02 s.", difficulty: "medium", source: "original" },

  { id: "gs3-bio-029", subject: "biology", topic: "metabolism", stimulusId: "gs3-b8", stimulus: { kind: "html", content: ST8, attribution: "Original" }, stem: "The enzyme's optimum conditions are closest to:", format: "single_best", options: ["10°C and pH 2", "55°C and pH 10", "45°C and pH 8", "37°C and pH 7"], answer: 3, explanation: "Activity peaks at 100% at 37 degrees C and at pH 7, the body-matched optimum for this gut enzyme.", difficulty: "easy", source: "original" },
  { id: "gs3-bio-030", subject: "biology", topic: "metabolism", stimulusId: "gs3-b8", stimulus: { kind: "html", content: ST8, attribution: "Original" }, stem: "Activity falls almost to zero at 55°C but only to 20% at 10°C. The difference is because high temperature:", format: "single_best", options: ["dilutes the enzyme", "adds substrate", "raises the pH", "permanently denatures (unfolds) the enzyme, whereas cold only slows it reversibly"], answer: 3, explanation: "Cold slows molecular motion but the enzyme recovers on warming; excessive heat breaks the bonds holding the enzyme's shape, denaturing it irreversibly, so activity collapses.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-031", subject: "biology", topic: "metabolism", stimulusId: "gs3-b8", stimulus: { kind: "html", content: ST8, attribution: "Original" }, stem: "Moving from pH 7 to pH 2 (as in the stomach) reduces this enzyme's activity from 100% to:", format: "single_best", options: ["5%", "70%", "40%", "0%, with the enzyme destroyed"], answer: 0, explanation: "The table reads 5% activity at pH 2. The molecule is far from its optimum but the table does not state it is destroyed.", difficulty: "easy", source: "original" },
  { id: "gs3-bio-032", subject: "biology", topic: "macromolecules", stimulusId: "gs3-b8", stimulus: { kind: "html", content: ST8, attribution: "Original" }, stem: "Denaturation by heat or extreme pH directly disrupts the enzyme's:", format: "single_best", options: ["sequence of amino acids (primary structure)", "folded three-dimensional shape", "number of amino acids", "genetic code"], answer: 1, explanation: "Denaturation breaks the weak bonds that hold the folded shape, destroying the active site. The amino-acid sequence (covalent peptide bonds) is not broken.", difficulty: "medium", source: "original" },

  { id: "gs3-bio-033", subject: "biology", topic: "genetics", stimulusId: "gs3-b9", stimulus: { kind: "html", content: ST9, attribution: "Original" }, stem: "After 4 PCR cycles, the number of copies is:", format: "single_best", options: ["16000", "4000", "5000", "8000"], answer: 0, explanation: "Each cycle doubles the count: 1000 x 2^4 = 1000 x 16 = 16000.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-034", subject: "biology", topic: "genetics", stimulusId: "gs3-b9", stimulus: { kind: "html", content: ST9, attribution: "Original" }, stem: "To exceed one million copies starting from 1000, the smallest number of cycles needed is:", format: "single_best", options: ["20", "100", "1000", "10"], answer: 3, explanation: "A million-fold increase needs 2^n > 1000; 2^10 = 1024 > 1000, so 10 cycles take 1000 to just over one million.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-035", subject: "biology", topic: "macromolecules", stimulusId: "gs3-b9", stimulus: { kind: "html", content: ST9, attribution: "Original" }, stem: "A double-stranded DNA sample is found to be 30% adenine (A). The percentage of guanine (G) is:", format: "single_best", options: ["20%", "30%", "70%", "60%"], answer: 0, explanation: "A pairs with T, so T = 30% and A + T = 60%. The remaining 40% is G + C, split equally, so G = 20%.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-036", subject: "biology", topic: "macromolecules", stimulusId: "gs3-b9", stimulus: { kind: "html", content: ST9, attribution: "Original" }, stem: "Chargaff's rule (A = T and G = C) is a direct consequence of:", format: "single_best", options: ["DNA being single-stranded", "the sugar-phosphate backbone", "the two strands being complementary base-paired", "the genetic code being triplet"], answer: 2, explanation: "Because every A on one strand pairs with a T on the other (and G with C), the totals of paired bases must be equal in double-stranded DNA.", difficulty: "medium", source: "original" },

  { id: "gs3-bio-037", subject: "biology", topic: "metabolism", stimulusId: "gs3-b10", stimulus: { kind: "html", content: ST10, attribution: "Original" }, stem: "At low CO2, raising the light intensity above 4 units produces:", format: "single_best", options: ["a continued rise in rate", "no further rise in rate", "a fall in rate", "a doubling of rate"], answer: 1, explanation: "At low CO2 the rate plateaus at 30 from intensity 4 onward: extra light no longer helps because something else now limits the rate.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-038", subject: "biology", topic: "metabolism", stimulusId: "gs3-b10", stimulus: { kind: "html", content: ST10, attribution: "Original" }, stem: "On the plateau at low CO2, the factor limiting photosynthesis is most likely:", format: "single_best", options: ["carbon dioxide concentration", "light intensity", "temperature", "water supply"], answer: 0, explanation: "Raising light gives no further rise, but raising CO2 does (the high-CO2 column keeps climbing), so CO2 is the limiting factor on the low-CO2 plateau.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-039", subject: "biology", topic: "metabolism", stimulusId: "gs3-b10", stimulus: { kind: "html", content: ST10, attribution: "Original" }, stem: "At light intensities 1 and 2, the two CO2 conditions give identical rates. This shows that there:", format: "single_best", options: ["CO2 is limiting", "light is limiting, so extra CO2 cannot help", "temperature is limiting", "the plant is not photosynthesising"], answer: 1, explanation: "When light is scarce it sets the ceiling; adding CO2 makes no difference, which is why both columns read the same at low light.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-040", subject: "biology", topic: "metabolism", stimulusId: "gs3-b10", stimulus: { kind: "html", content: ST10, attribution: "Original" }, stem: "This indicates that at 25°C and high light, the rate was also partly limited by:", format: "single_best", options: ["temperature", "light", "carbon dioxide", "oxygen"], answer: 0, explanation: "If warming raises the rate further, temperature was holding it back: at high light and high CO2, temperature became a co-limiting factor.", addedInfo: "The experiment at high CO2 is repeated at 35°C instead of 25°C, and every rate is higher.", difficulty: "medium", source: "original" },

  { id: "gs3-bio-041", subject: "biology", topic: "physiology", stimulusId: "gs3-b11", stimulus: { kind: "html", content: ST11, attribution: "Original" }, stem: "The stroke volume (blood ejected in one beat) is:", format: "single_best", options: ["70 mL", "50 mL", "120 mL", "170 mL"], answer: 0, explanation: "Stroke volume = end-of-filling volume minus end-of-ejection volume = 120 - 50 = 70 mL.", difficulty: "easy", source: "original" },
  { id: "gs3-bio-042", subject: "biology", topic: "physiology", stimulusId: "gs3-b11", stimulus: { kind: "html", content: ST11, attribution: "Original" }, stem: "Between 'end of filling' (8 mmHg) and 'start of ejection' (82 mmHg) the volume stays at 120 mL. During this phase:", format: "single_best", options: ["both valves are open", "both valves are closed, so volume cannot change as pressure rises", "blood is entering the ventricle", "the aortic valve is open"], answer: 1, explanation: "Pressure rises sharply with no volume change: this isovolumetric contraction occurs while both valves are shut, before the aortic valve opens at 80 mmHg.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-043", subject: "biology", topic: "physiology", stimulusId: "gs3-b11", stimulus: { kind: "html", content: ST11, attribution: "Original" }, stem: "At a heart rate of 70 beats per minute, the cardiac output is closest to:", format: "single_best", options: ["0.7 L/min", "8.4 L/min", "4.9 L/min", "70 L/min"], answer: 2, explanation: "Cardiac output = stroke volume x rate = 70 mL x 70 = 4900 mL/min = 4.9 L/min.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-044", subject: "biology", topic: "physiology", stimulusId: "gs3-b11", stimulus: { kind: "html", content: ST11, attribution: "Original" }, stem: "The aortic valve opens at the moment ventricular pressure reaches about:", format: "single_best", options: ["8 mmHg", "50 mmHg", "80 mmHg", "120 mmHg"], answer: 2, explanation: "The aortic valve opens once ventricular pressure exceeds aortic diastolic pressure, about 80 mmHg, which matches the 82 mmHg start-of-ejection value.", difficulty: "medium", source: "original" },

  { id: "gs3-bio-045", subject: "biology", topic: "physiology", stimulusId: "gs3-b12", stimulus: { kind: "html", content: ST12, attribution: "Original" }, stem: "Glucose falls to a relative concentration of 0 by the end of the proximal tubule. This means glucose is:", format: "single_best", options: ["completely reabsorbed back into the blood", "secreted into the urine", "destroyed in the tubule", "converted to urea"], answer: 0, explanation: "A healthy nephron reabsorbs all filtered glucose in the proximal tubule, so its concentration in the tubular fluid drops to zero.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-046", subject: "biology", topic: "physiology", stimulusId: "gs3-b12", stimulus: { kind: "html", content: ST12, attribution: "Original" }, stem: "Inulin is neither reabsorbed nor secreted, yet its relative concentration rises to 120 in the final urine. This rise is caused by:", format: "single_best", options: ["inulin being added to the filtrate", "inulin being broken down", "water being reabsorbed, concentrating the inulin left behind", "the kidney making new inulin"], answer: 2, explanation: "With the amount of inulin fixed, removing water concentrates it. A 120-fold rise means about 119 parts in 120 of the water has been reabsorbed (only 1 part in 120 remains).", difficulty: "hard", source: "original" },
  { id: "gs3-bio-047", subject: "biology", topic: "physiology", stimulusId: "gs3-b12", stimulus: { kind: "html", content: ST12, attribution: "Original" }, stem: "Urea reaches a relative concentration of 60 while inulin reaches 120. This shows that, unlike inulin, urea is:", format: "single_best", options: ["fully reabsorbed", "actively secreted", "not filtered at all", "partly reabsorbed (its rise lags behind the water loss)"], answer: 3, explanation: "If urea simply tracked water loss it would also reach 120. Reaching only 60 means about half the filtered urea was reabsorbed along the way.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-048", subject: "biology", topic: "physiology", stimulusId: "gs3-b12", stimulus: { kind: "html", content: ST12, attribution: "Original" }, stem: "A surge of ADH would cause the final-urine inulin concentration to:", format: "single_best", options: ["fall", "stay at 120", "rise even higher than 120", "become zero"], answer: 2, explanation: "More water reabsorbed means less water left to dilute the inulin, so its relative concentration in a smaller, more concentrated urine rises further.", addedInfo: "The hormone ADH (antidiuretic hormone) increases water reabsorption in the collecting duct.", difficulty: "medium", source: "original" },

  { id: "gs3-bio-049", subject: "biology", topic: "metabolism", stimulusId: "gs3-b13", stimulus: { kind: "html", content: ST13, attribution: "Original" }, stem: "Between 0 and 1 hour the count does not change. This lag phase is when the bacteria are:", format: "single_best", options: ["dying", "dividing at maximum rate", "running out of nutrients", "adjusting and synthesising enzymes before dividing"], answer: 3, explanation: "The flat start is the lag phase: cells are adapting to the medium and gearing up to divide, so numbers have not yet risen.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-050", subject: "biology", topic: "metabolism", stimulusId: "gs3-b13", stimulus: { kind: "html", content: ST13, attribution: "Original" }, stem: "During the exponential phase (hours 1 to 4) the population doubles every:", format: "single_best", options: ["0.5 h", "2 h", "4 h", "1 h"], answer: 3, explanation: "1 to 2 to 4 to 8 million over hours 1, 2, 3, 4: the count doubles each hour, so the doubling time is 1 hour.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-051", subject: "biology", topic: "metabolism", stimulusId: "gs3-b13", stimulus: { kind: "html", content: ST13, attribution: "Original" }, stem: "Growth slows sharply after hour 4 (8 to 15 to 16 million). In a sealed flask of fixed nutrient, this is best explained by:", format: "single_best", options: ["the bacteria mutating", "nutrient depletion and waste build-up limiting further growth", "a fall in temperature", "the count being measured wrongly"], answer: 1, explanation: "In a closed flask, exponential growth cannot continue indefinitely: running low on nutrients and accumulating waste flatten the curve toward a stationary phase.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-052", subject: "biology", topic: "metabolism", stimulusId: "gs3-b13", stimulus: { kind: "html", content: ST13, attribution: "Original" }, stem: "If the exponential doubling had continued unchecked from hour 4, the count at hour 6 would have been:", format: "single_best", options: ["16 million", "24 million", "32 million", "64 million"], answer: 2, explanation: "From 8 million at hour 4, doubling each hour gives 16 at hour 5 and 32 million at hour 6 (the real count was lower because growth slowed).", difficulty: "hard", source: "original" },

  { id: "gs3-bio-053", subject: "biology", topic: "cells_membranes", stimulusId: "gs3-b14", stimulus: { kind: "html", content: ST14, attribution: "Original" }, stem: "The overall dilution factor of the blood (step 1 then step 2 combined) is:", format: "single_best", options: ["1 in 100", "1 in 110", "1 in 1000", "1 in 10"], answer: 2, explanation: "Step 1: 0.1 mL into 10 mL total = 1 in 100. Step 2: 0.1 mL into 1.0 mL total = 1 in 10. Combined = 1/100 x 1/10 = 1 in 1000.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-054", subject: "biology", topic: "cells_membranes", stimulusId: "gs3-b14", stimulus: { kind: "html", content: ST14, attribution: "Original" }, stem: "The final dilution contains 250 cells in 0.0001 mL. Its cell concentration is:", format: "single_best", options: ["2.5 x 10^4 per mL", "2.5 x 10^5 per mL", "2.5 x 10^6 per mL", "2.5 x 10^7 per mL"], answer: 2, explanation: "250 / 0.0001 mL = 250 x 10^4 = 2.5 x 10^6 cells per mL.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-055", subject: "biology", topic: "cells_membranes", stimulusId: "gs3-b14", stimulus: { kind: "html", content: ST14, attribution: "Original" }, stem: "The concentration of cells in the original undiluted blood is therefore:", format: "single_best", options: ["2.5 x 10^6 per mL", "2.5 x 10^3 per mL", "2.5 x 10^7 per mL", "2.5 x 10^9 per mL"], answer: 3, explanation: "Multiply the final concentration by the 1000-fold dilution: 2.5 x 10^6 x 1000 = 2.5 x 10^9 cells per mL.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-056", subject: "biology", topic: "cells_membranes", stimulusId: "gs3-b14", stimulus: { kind: "html", content: ST14, attribution: "Original" }, stem: "If only step 1 had been done (no step 2), the blood concentration calculated from the same chamber count would have been:", format: "single_best", options: ["unchanged", "10 times too high", "100 times too high", "10 times too low"], answer: 3, explanation: "Skipping the further 1-in-10 dilution means you multiply by only 100 instead of 1000, giving a value 10 times too low.", difficulty: "hard", source: "original" },

  { id: "gs3-bio-057", subject: "biology", topic: "physiology", stimulusId: "gs3-b15", stimulus: { kind: "html", content: ST15, attribution: "Original" }, stem: "The vital capacity (the maximum air that can be exhaled after a maximum breath in) is:", format: "single_best", options: ["3500 mL", "4600 mL", "5800 mL", "1200 mL"], answer: 1, explanation: "Vital capacity = tidal + inspiratory reserve + expiratory reserve = 500 + 3000 + 1100 = 4600 mL (residual volume is excluded as it cannot be exhaled).", difficulty: "medium", source: "original" },
  { id: "gs3-bio-058", subject: "biology", topic: "physiology", stimulusId: "gs3-b15", stimulus: { kind: "html", content: ST15, attribution: "Original" }, stem: "The total lung capacity is:", format: "single_best", options: ["4600 mL", "5800 mL", "3500 mL", "500 mL"], answer: 1, explanation: "Total lung capacity = all four volumes = 500 + 3000 + 1100 + 1200 = 5800 mL.", difficulty: "easy", source: "original" },
  { id: "gs3-bio-059", subject: "biology", topic: "physiology", stimulusId: "gs3-b15", stimulus: { kind: "html", content: ST15, attribution: "Original" }, stem: "At rest (12 breaths/min of tidal volume), the volume of air breathed per minute is:", format: "single_best", options: ["600 mL", "55200 mL", "4600 mL", "6000 mL"], answer: 3, explanation: "Minute ventilation = tidal volume x rate = 500 mL x 12 = 6000 mL/min.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-060", subject: "biology", topic: "physiology", stimulusId: "gs3-b15", stimulus: { kind: "html", content: ST15, attribution: "Original" }, stem: "The volume of fresh air reaching the alveoli each minute is:", format: "single_best", options: ["6000 mL", "4200 mL", "1800 mL", "350 mL"], answer: 1, explanation: "Useful air per breath = 500 - 150 = 350 mL. Per minute = 350 x 12 = 4200 mL.", addedInfo: "Of each 500 mL breath, the first 150 mL only fills the conducting airways (dead space) and never reaches the gas-exchanging alveoli.", difficulty: "hard", source: "original" },

  { id: "gs3-bio-061", subject: "biology", topic: "physiology", stimulusId: "gs3-b16", stimulus: { kind: "html", content: ST16, attribution: "Original" }, stem: "After a meal, blood glucose is high and insulin is high. This relationship is an example of:", format: "single_best", options: ["positive feedback", "an irreversible change", "a random fluctuation", "a corrective (negative-feedback) response"], answer: 3, explanation: "A rise in glucose triggers insulin, which lowers glucose back toward normal: the response opposes the change, which is negative feedback.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-062", subject: "biology", topic: "physiology", stimulusId: "gs3-b16", stimulus: { kind: "html", content: ST16, attribution: "Original" }, stem: "During the overnight fast, glucagon is high. Its role is to:", format: "single_best", options: ["drive glucose into cells", "release glucose from the liver to raise blood glucose", "lower blood glucose", "stop the heart"], answer: 1, explanation: "When glucose falls during fasting, glucagon mobilises stored glucose from the liver, raising blood glucose back toward 5 mmol/L.", difficulty: "easy", source: "original" },
  { id: "gs3-bio-063", subject: "biology", topic: "physiology", stimulusId: "gs3-b16", stimulus: { kind: "html", content: ST16, attribution: "Original" }, stem: "After a meal, this person's blood glucose would most likely:", format: "single_best", options: ["fall too low", "rise much higher than 8 mmol/L and stay elevated", "stay exactly at 5 mmol/L", "be unaffected by the meal"], answer: 1, explanation: "Without insulin, glucose cannot be cleared into cells efficiently, so after a meal it climbs well above normal and remains high.", addedInfo: "A person with type 1 diabetes makes almost no insulin.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-064", subject: "biology", topic: "physiology", stimulusId: "gs3-b16", stimulus: { kind: "html", content: ST16, attribution: "Original" }, stem: "Insulin and glucagon have opposite effects and are rarely both high at once. Two hormones acting in opposition like this are best described as:", format: "single_best", options: ["synergistic", "antagonistic", "identical", "enzymatic"], answer: 1, explanation: "Hormones with opposing actions on the same variable are antagonistic, allowing fine two-way control of blood glucose.", difficulty: "easy", source: "original" },

  { id: "gs3-bio-065", subject: "biology", topic: "macromolecules", stimulusId: "gs3-b17", stimulus: { kind: "html", content: ST17, attribution: "Original" }, stem: "A laboratory test detects nitrogen in an unknown macromolecule. According to the table it could be a protein or a:", format: "single_best", options: ["polysaccharide", "triglyceride", "nucleic acid", "monosaccharide"], answer: 2, explanation: "Only proteins and nucleic acids contain nitrogen in this table; polysaccharides and triglycerides do not.", difficulty: "easy", source: "original" },
  { id: "gs3-bio-066", subject: "biology", topic: "macromolecules", stimulusId: "gs3-b17", stimulus: { kind: "html", content: ST17, attribution: "Original" }, stem: "All four families are assembled by condensation. To break any of these polymers back into monomers, a cell uses:", format: "single_best", options: ["further condensation", "oxidation by oxygen", "hydrolysis (adding water)", "freezing"], answer: 2, explanation: "Condensation joins monomers and releases water; the reverse, hydrolysis, splits the bond by adding water back.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-067", subject: "biology", topic: "macromolecules", stimulusId: "gs3-b17", stimulus: { kind: "html", content: ST17, attribution: "Original" }, stem: "A triglyceride is the only family here NOT made of repeating identical monomers. Its building blocks are:", format: "single_best", options: ["many identical sugars", "one glycerol joined to three fatty acids by ester bonds", "nucleotides", "amino acids"], answer: 1, explanation: "A triglyceride is one glycerol esterified to three fatty acids, so it is not a polymer of one repeating monomer like the others.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-068", subject: "biology", topic: "macromolecules", stimulusId: "gs3-b17", stimulus: { kind: "html", content: ST17, attribution: "Original" }, stem: "Forming a single chain of 200 nucleotides into a nucleic acid releases how many water molecules?", format: "single_best", options: ["199", "200", "201", "100"], answer: 0, explanation: "Joining n monomers into one chain forms n - 1 bonds, each releasing one water: 200 - 1 = 199.", difficulty: "medium", source: "original" },

  { id: "gs3-bio-069", subject: "biology", topic: "genetics", stimulusId: "gs3-b18", stimulus: { kind: "html", content: ST18, attribution: "Original" }, stem: "The sequence AUG-GAA-AAA-UUU translates to:", format: "single_best", options: ["Methionine - Lysine - Glutamate - Phenylalanine", "Methionine - Glutamate - Lysine - Phenylalanine", "Glutamate - Lysine - Phenylalanine - Stop", "Methionine - Glutamate - Phenylalanine - Lysine"], answer: 1, explanation: "Reading the table: AUG = Met (start), GAA = Glutamate, AAA = Lysine, UUU = Phenylalanine.", difficulty: "easy", source: "original" },
  { id: "gs3-bio-070", subject: "biology", topic: "genetics", stimulusId: "gs3-b18", stimulus: { kind: "html", content: ST18, attribution: "Original" }, stem: "If the third base of the second codon changes from GAA to GAG, the protein:", format: "single_best", options: ["is unchanged, as GAG also codes glutamate (a silent mutation)", "gains a stop codon", "changes its first amino acid", "is read in a new frame"], answer: 0, explanation: "GAA and GAG both code glutamate, so the amino-acid sequence is unchanged: this is a silent mutation.", difficulty: "medium", source: "original" },
  { id: "gs3-bio-071", subject: "biology", topic: "genetics", stimulusId: "gs3-b18", stimulus: { kind: "html", content: ST18, attribution: "Original" }, stem: "If a single extra base is inserted right after the start codon, the most likely result is:", format: "single_best", options: ["the whole downstream reading frame shifts, scrambling every later codon", "one amino acid changes only", "no change at all", "the protein gets one amino acid longer but is otherwise normal"], answer: 0, explanation: "Inserting one base shifts the triplet reading frame, so every codon downstream is misread: a frameshift mutation, usually far more damaging than a single substitution.", difficulty: "hard", source: "original" },
  { id: "gs3-bio-072", subject: "biology", topic: "genetics", stimulusId: "gs3-b18", stimulus: { kind: "html", content: ST18, attribution: "Original" }, stem: "A mutation changing the third codon from AAA to UAA would:", format: "single_best", options: ["swap lysine for phenylalanine", "have no effect", "introduce a premature stop, truncating the protein", "lengthen the protein"], answer: 2, explanation: "UAA is a stop codon, so translation would halt early at the third position, producing a shortened (truncated) protein: a nonsense mutation.", difficulty: "medium", source: "original" },

  { id: "gs3-gc-001", subject: "general_chemistry", topic: "acids_bases", stimulusId: "gs3-c1", stimulus: { kind: "html", content: ST19, attribution: "Original" }, stem: "At the half-equivalence point (25.0 mL) the weak acid's pH equals its pKa. Its acid dissociation constant Ka is therefore:", format: "single_best", options: ["1 x 10^-3", "1 x 10^-5", "1 x 10^-7", "1 x 10^-9"], answer: 1, explanation: "At half-equivalence [HA] = [A-], so pH = pKa. The weak-acid pH is 5.0 there, so pKa = 5 and Ka = 1 x 10^-5.", difficulty: "hard", source: "original" },
  { id: "gs3-gc-002", subject: "general_chemistry", topic: "acids_bases", stimulusId: "gs3-c1", stimulus: { kind: "html", content: ST19, attribution: "Original" }, stem: "The weak acid's equivalence-point pH is 8.9, not 7. The reason is that at equivalence the solution contains:", format: "single_best", options: ["excess strong acid", "only neutral water", "excess NaOH", "the conjugate base A-, which is itself weakly basic"], answer: 3, explanation: "At equivalence all HA has become A-, the conjugate base of a weak acid. A- reacts slightly with water to give OH-, making the solution basic (pH above 7).", difficulty: "hard", source: "original" },
  { id: "gs3-gc-003", subject: "general_chemistry", topic: "acids_bases", stimulusId: "gs3-c1", stimulus: { kind: "html", content: ST19, attribution: "Original" }, stem: "The best indicator for the weak-acid titration is:", format: "single_best", options: ["methyl red, because it changes at low pH", "phenolphthalein, because its range (8 to 10) brackets the equivalence pH of 8.9", "either works equally well", "neither, an indicator cannot be used"], answer: 1, explanation: "The indicator must change colour at the equivalence pH (8.9). Phenolphthalein (8.0 to 10.0) does; methyl red (4.2 to 6.3) would change far too early.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-004", subject: "general_chemistry", topic: "acids_bases", stimulusId: "gs3-c1", stimulus: { kind: "html", content: ST19, attribution: "Original" }, stem: "At 60.0 mL both acids have pH 12.0. This convergence happens because, past equivalence, the pH is set by:", format: "single_best", options: ["the strength of the original acid", "the excess NaOH, which is the same in both flasks", "the indicator", "the temperature"], answer: 1, explanation: "Beyond equivalence the acid is fully neutralised, so the pH depends only on the excess strong base added, which is identical in both titrations.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-005", subject: "general_chemistry", topic: "acids_bases", stimulusId: "gs3-c1", stimulus: { kind: "html", content: ST19, attribution: "Original" }, stem: "Compared with acid HA, this third acid is:", format: "single_best", options: ["weaker, with a smaller Ka", "identical in strength", "not an acid", "stronger, with a larger Ka (1 x 10^-3)"], answer: 3, explanation: "Half-equivalence pH = pKa = 3.0, so Ka = 1 x 10^-3, which is 100 times larger than HA's 1 x 10^-5: the third acid is the stronger one.", addedInfo: "A third acid is titrated the same way and its half-equivalence pH is found to be 3.0.", difficulty: "hard", source: "original" },

  { id: "gs3-gc-006", subject: "general_chemistry", topic: "kinetics_equilibrium", stimulusId: "gs3-c2", stimulus: { kind: "html", content: ST20, attribution: "Original" }, stem: "As temperature rises, Kc falls. This shows the forward reaction is:", format: "single_best", options: ["endothermic", "neither", "impossible", "exothermic"], answer: 3, explanation: "A falling K with rising temperature means heat favours the reverse reaction, so the forward reaction releases heat: it is exothermic.", difficulty: "hard", source: "original" },
  { id: "gs3-gc-007", subject: "general_chemistry", topic: "kinetics_equilibrium", stimulusId: "gs3-c2", stimulus: { kind: "html", content: ST20, attribution: "Original" }, stem: "Raising the temperature from 200 to 400°C shifts the position of equilibrium:", format: "single_best", options: ["toward the reactants (A and B)", "toward the products (C)", "not at all", "first one way then the other"], answer: 0, explanation: "For an exothermic forward reaction, added heat shifts equilibrium back toward reactants, consistent with the smaller K (2) at 400 degrees C.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-008", subject: "general_chemistry", topic: "kinetics_equilibrium", stimulusId: "gs3-c2", stimulus: { kind: "html", content: ST20, attribution: "Original" }, stem: "Increasing the total pressure (by compression) on A(g) + B(g) ⇌ 2C(g) shifts the equilibrium:", format: "single_best", options: ["toward the products", "toward the reactants", "in an unpredictable way", "not at all, because both sides have the same number of gas molecules"], answer: 3, explanation: "Pressure shifts equilibrium toward the side with fewer gas molecules. Here both sides have 2 molecules, so pressure has no effect.", difficulty: "hard", source: "original" },
  { id: "gs3-gc-009", subject: "general_chemistry", topic: "kinetics_equilibrium", stimulusId: "gs3-c2", stimulus: { kind: "html", content: ST20, attribution: "Original" }, stem: "Adding a catalyst to this system at 300°C would change Kc to:", format: "single_best", options: ["a larger value", "a smaller value", "10 (unchanged)", "zero"], answer: 2, explanation: "A catalyst speeds both directions equally and does not alter the equilibrium constant; Kc stays 10 at 300 degrees C, equilibrium is simply reached sooner.", difficulty: "medium", source: "original" },

  { id: "gs3-gc-010", subject: "general_chemistry", topic: "kinetics_equilibrium", stimulusId: "gs3-c3", stimulus: { kind: "html", content: ST21, attribution: "Original" }, stem: "Comparing experiments 1 and 2, doubling [A] (at fixed [B]) makes the rate go from 2 to 8. The order with respect to A is:", format: "single_best", options: ["zero", "first", "second", "third"], answer: 2, explanation: "Doubling [A] multiplies the rate by 4 = 2^2, so the reaction is second order in A.", difficulty: "hard", source: "original" },
  { id: "gs3-gc-011", subject: "general_chemistry", topic: "kinetics_equilibrium", stimulusId: "gs3-c3", stimulus: { kind: "html", content: ST21, attribution: "Original" }, stem: "Comparing experiments 1 and 3, the order with respect to B is:", format: "single_best", options: ["zero", "first", "second", "third"], answer: 1, explanation: "Doubling [B] (2 to 4) doubles the rate = 2^1, so the reaction is first order in B.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-012", subject: "general_chemistry", topic: "kinetics_equilibrium", stimulusId: "gs3-c3", stimulus: { kind: "html", content: ST21, attribution: "Original" }, stem: "The overall order of the reaction is:", format: "single_best", options: ["first", "second", "third", "fourth"], answer: 2, explanation: "Overall order = order in A + order in B = 2 + 1 = 3.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-013", subject: "general_chemistry", topic: "kinetics_equilibrium", stimulusId: "gs3-c3", stimulus: { kind: "html", content: ST21, attribution: "Original" }, stem: "If both [A] and [B] are doubled at once (from experiment 1), the new rate is:", format: "single_best", options: ["8", "12", "16", "6"], answer: 2, explanation: "Rate scales as [A]^2[B]. Doubling both multiplies the rate by 2^2 x 2 = 8, so 2 x 8 = 16.", difficulty: "hard", source: "original" },

  { id: "gs3-gc-014", subject: "general_chemistry", topic: "electrochemistry", stimulusId: "gs3-c4", stimulus: { kind: "html", content: ST22, attribution: "Original" }, stem: "The strongest oxidising agent in the table is:", format: "single_best", options: ["Ag+", "Mg^2+", "Zn^2+", "H+"], answer: 0, explanation: "The strongest oxidising agent is the species most easily reduced, i.e. the most positive E. Ag+ at +0.80 V is highest.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-015", subject: "general_chemistry", topic: "electrochemistry", stimulusId: "gs3-c4", stimulus: { kind: "html", content: ST22, attribution: "Original" }, stem: "A cell is built from a Zn electrode and a Cu electrode. Its standard EMF is:", format: "single_best", options: ["1.10 V", "0.42 V", "0.34 V", "2.37 V"], answer: 0, explanation: "Cu (higher E) is the cathode, Zn the anode: EMF = 0.34 - (-0.76) = 1.10 V.", difficulty: "hard", source: "original" },
  { id: "gs3-gc-016", subject: "general_chemistry", topic: "electrochemistry", stimulusId: "gs3-c4", stimulus: { kind: "html", content: ST22, attribution: "Original" }, stem: "In that Zn/Cu cell, the metal that is oxidised (the anode) is:", format: "single_best", options: ["copper", "silver", "zinc", "hydrogen"], answer: 2, explanation: "The more easily oxidised metal (more negative E) is the anode. Zn at -0.76 V is oxidised, releasing electrons.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-017", subject: "general_chemistry", topic: "electrochemistry", stimulusId: "gs3-c4", stimulus: { kind: "html", content: ST22, attribution: "Original" }, stem: "Which metal will NOT react with dilute acid (2H+) to release hydrogen gas?", format: "single_best", options: ["magnesium", "zinc", "all three react", "silver"], answer: 3, explanation: "Only metals with E below 0 (Mg, Zn) are oxidised by H+. Silver (+0.80 V) is above hydrogen and will not displace H2 from acid.", difficulty: "hard", source: "original" },
  { id: "gs3-gc-018", subject: "general_chemistry", topic: "electrochemistry", stimulusId: "gs3-c4", stimulus: { kind: "html", content: ST22, attribution: "Original" }, stem: "If a strip of zinc metal is dipped into copper(II) sulfate solution, the prediction is that:", format: "single_best", options: ["no reaction occurs", "zinc ions are reduced to zinc", "the solution turns more blue", "copper metal deposits as Zn dissolves, because the reaction has a positive EMF"], answer: 3, explanation: "Zn is oxidised and Cu2+ reduced (EMF +1.10 V, spontaneous), so copper plates out and zinc dissolves, fading the blue colour.", difficulty: "medium", source: "original" },

  { id: "gs3-gc-019", subject: "general_chemistry", topic: "gases", stimulusId: "gs3-c5", stimulus: { kind: "html", content: ST23, attribution: "Original" }, stem: "Burning 24 L of CH4 completely requires what volume of O2 at the same conditions?", format: "single_best", options: ["48 L", "24 L", "12 L", "96 L"], answer: 0, explanation: "The equation needs 2 mol O2 per mol CH4. Equal volumes hold equal moles, so 24 L CH4 needs 48 L O2.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-020", subject: "general_chemistry", topic: "gases", stimulusId: "gs3-c5", stimulus: { kind: "html", content: ST23, attribution: "Original" }, stem: "What volume of CO2 is produced by completely burning 48 g of CH4?", format: "single_best", options: ["24 L", "48 L", "72 L", "96 L"], answer: 2, explanation: "48 g / 16 g/mol = 3 mol CH4, giving 3 mol CO2. At 24 L/mol that is 72 L.", difficulty: "hard", source: "original" },
  { id: "gs3-gc-021", subject: "general_chemistry", topic: "stoichiometry", stimulusId: "gs3-c5", stimulus: { kind: "html", content: ST23, attribution: "Original" }, stem: "The limiting reagent is:", format: "single_best", options: ["CH4", "neither, they are exactly matched", "CO2", "O2"], answer: 3, explanation: "2 mol CH4 would need 4 mol O2, but only 3 mol O2 is present, so O2 runs out first and is limiting.", addedInfo: "Now 2 mol of CH4 is mixed with only 3 mol of O2 and ignited.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-022", subject: "general_chemistry", topic: "stoichiometry", stimulusId: "gs3-c5", stimulus: { kind: "html", content: ST23, attribution: "Original" }, stem: "The amount of CO2 formed is:", format: "single_best", options: ["2 mol", "1.5 mol", "3 mol", "4 mol"], answer: 1, explanation: "O2 limits: 3 mol O2 x (1 mol CO2 / 2 mol O2) = 1.5 mol CO2.", addedInfo: "Still using 2 mol CH4 with 3 mol O2.", difficulty: "hard", source: "original" },

  { id: "gs3-gc-023", subject: "general_chemistry", topic: "thermodynamics", stimulusId: "gs3-c6", stimulus: { kind: "html", content: ST24, attribution: "Original" }, stem: "Which reaction is spontaneous at every temperature?", format: "single_best", options: ["R1 (ΔH negative, ΔS positive)", "R2", "R3", "R4"], answer: 0, explanation: "If delta H is negative and delta S positive, delta G = delta H - T x delta S is negative at all temperatures. That is R1.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-024", subject: "general_chemistry", topic: "thermodynamics", stimulusId: "gs3-c6", stimulus: { kind: "html", content: ST24, attribution: "Original" }, stem: "Which reaction is non-spontaneous at every temperature?", format: "single_best", options: ["R1", "R3", "R2 (ΔH positive, ΔS negative)", "R4"], answer: 2, explanation: "With delta H positive and delta S negative, delta G is positive at all T, so R2 never proceeds spontaneously.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-025", subject: "general_chemistry", topic: "thermodynamics", stimulusId: "gs3-c6", stimulus: { kind: "html", content: ST24, attribution: "Original" }, stem: "Reaction R3 becomes spontaneous above a temperature of about:", format: "single_best", options: ["500 K", "50 K", "200 K", "2000 K"], answer: 0, explanation: "Spontaneity needs T x delta S > delta H: T > (100 000 J)/(200 J/K) = 500 K.", difficulty: "hard", source: "original" },
  { id: "gs3-gc-026", subject: "general_chemistry", topic: "thermodynamics", stimulusId: "gs3-c6", stimulus: { kind: "html", content: ST24, attribution: "Original" }, stem: "Reaction R4 (ΔH negative, ΔS negative) is spontaneous:", format: "single_best", options: ["only at high temperature", "at all temperatures", "only at low temperature", "at no temperature"], answer: 2, explanation: "With both terms negative, the unfavourable -T x delta S grows with T. So delta G is negative only at low temperature (below 500 K here).", difficulty: "hard", source: "original" },

  { id: "gs3-gc-027", subject: "general_chemistry", topic: "solutions", stimulusId: "gs3-c7", stimulus: { kind: "html", content: ST25, attribution: "Original" }, stem: "The molar solubility of AgCl (Ksp = 1.0 x 10^-10) in pure water is:", format: "single_best", options: ["1.0 x 10^-10 mol/L", "1.0 x 10^-5 mol/L", "1.0 x 10^-20 mol/L", "0.5 x 10^-10 mol/L"], answer: 1, explanation: "For AgCl, Ksp = s x s = s^2, so s = sqrt(1.0 x 10^-10) = 1.0 x 10^-5 mol/L.", difficulty: "hard", source: "original" },
  { id: "gs3-gc-028", subject: "general_chemistry", topic: "solutions", stimulusId: "gs3-c7", stimulus: { kind: "html", content: ST25, attribution: "Original" }, stem: "Comparing AgCl and AgBr, the less soluble salt is:", format: "single_best", options: ["AgCl, because its Ksp is larger", "they are equally soluble", "cannot be determined", "AgBr, because its Ksp is smaller"], answer: 3, explanation: "A smaller Ksp means a smaller molar solubility for these 1:1 salts. AgBr (1.0 x 10^-12) is the less soluble.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-029", subject: "general_chemistry", topic: "solutions", stimulusId: "gs3-c7", stimulus: { kind: "html", content: ST25, attribution: "Original" }, stem: "Adding solid NaCl to a saturated AgCl solution will:", format: "single_best", options: ["decrease AgCl solubility (the common-ion effect)", "increase AgCl solubility", "have no effect", "raise the Ksp"], answer: 0, explanation: "Extra Cl- (a common ion) pushes the equilibrium toward solid AgCl, lowering the amount of dissolved Ag+: the common-ion effect.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-030", subject: "general_chemistry", topic: "solutions", stimulusId: "gs3-c7", stimulus: { kind: "html", content: ST25, attribution: "Original" }, stem: "Equal volumes of 2 x 10^-4 M AgNO3 and 2 x 10^-4 M NaCl are mixed (each halved on mixing to 1 x 10^-4 M). Does AgCl precipitate?", format: "single_best", options: ["No, because Q is below Ksp", "Yes, because Q = 1 x 10^-8 exceeds Ksp", "No, because the ions cannot meet", "Only if heated"], answer: 1, explanation: "Q = [Ag+][Cl-] = (1 x 10^-4)(1 x 10^-4) = 1 x 10^-8, which is far above Ksp (1 x 10^-10), so a precipitate forms.", difficulty: "hard", source: "original" },

  { id: "gs3-gc-031", subject: "general_chemistry", topic: "stoichiometry", stimulusId: "gs3-c8", stimulus: { kind: "html", content: ST26, attribution: "Original" }, stem: "The oxidation number of sulfur in the sulfate ion, SO4^2-, is:", format: "single_best", options: ["+2", "+4", "-2", "+6"], answer: 3, explanation: "Four oxygens give 4 x (-2) = -8. For the total to equal the ion charge -2, sulfur must be +6.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-032", subject: "general_chemistry", topic: "stoichiometry", stimulusId: "gs3-c8", stimulus: { kind: "html", content: ST26, attribution: "Original" }, stem: "The oxidation number of chromium in the dichromate ion, Cr2O7^2-, is:", format: "single_best", options: ["+3", "+7", "+12", "+6"], answer: 3, explanation: "Seven oxygens give -14. With overall charge -2, the two Cr sum to +12, so each Cr is +6.", difficulty: "hard", source: "original" },
  { id: "gs3-gc-033", subject: "general_chemistry", topic: "stoichiometry", stimulusId: "gs3-c8", stimulus: { kind: "html", content: ST26, attribution: "Original" }, stem: "In the reaction Zn + Cu^2+ → Zn^2+ + Cu, the reducing agent is:", format: "single_best", options: ["Cu^2+", "Zn^2+", "Cu", "Zn"], answer: 3, explanation: "Zn loses electrons (0 to +2), so it is oxidised and therefore acts as the reducing agent (it donates electrons to Cu2+).", difficulty: "medium", source: "original" },
  { id: "gs3-gc-034", subject: "general_chemistry", topic: "stoichiometry", stimulusId: "gs3-c8", stimulus: { kind: "html", content: ST26, attribution: "Original" }, stem: "In 2H2 + O2 → 2H2O, each oxygen atom is:", format: "single_best", options: ["oxidised, gaining 2 electrons", "reduced, gaining 2 electrons", "oxidised, losing 2 electrons", "unchanged"], answer: 1, explanation: "Oxygen goes from 0 in O2 to -2 in water, a gain of 2 electrons per atom: it is reduced.", difficulty: "medium", source: "original" },

  { id: "gs3-gc-035", subject: "general_chemistry", topic: "solutions", stimulusId: "gs3-c9", stimulus: { kind: "html", content: ST27, attribution: "Original" }, stem: "At equal molality (1 m), which solute lowers the freezing point of water the most?", format: "single_best", options: ["glucose", "CaCl2", "NaCl", "all the same"], answer: 1, explanation: "Freezing-point depression scales with i, the number of particles. CaCl2 gives i = 3 (one Ca2+ and two Cl-), the most particles.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-036", subject: "general_chemistry", topic: "solutions", stimulusId: "gs3-c9", stimulus: { kind: "html", content: ST27, attribution: "Original" }, stem: "The freezing point of a 1 m NaCl solution is about:", format: "single_best", options: ["-1.86 °C", "-3.72 °C", "-5.58 °C", "0 °C"], answer: 1, explanation: "delta T = i x Kf x m = 2 x 1.86 x 1 = 3.72, so the solution freezes at about -3.72 degrees C.", difficulty: "hard", source: "original" },
  { id: "gs3-gc-037", subject: "general_chemistry", topic: "solutions", stimulusId: "gs3-c9", stimulus: { kind: "html", content: ST27, attribution: "Original" }, stem: "To depress the freezing point by the same amount as 1 m CaCl2, glucose would need a molality of about:", format: "single_best", options: ["3 m", "1 m", "2 m", "0.3 m"], answer: 0, explanation: "CaCl2 gives 3 particles per unit; glucose gives 1. To match 3 x 1.86, glucose must be 3 m.", difficulty: "hard", source: "original" },
  { id: "gs3-gc-038", subject: "general_chemistry", topic: "solutions", stimulusId: "gs3-c9", stimulus: { kind: "html", content: ST27, attribution: "Original" }, stem: "These freezing-point effects depend on the number of dissolved particles, not their identity. Such properties are called:", format: "single_best", options: ["colligative properties", "catalytic properties", "covalent properties", "intensive properties"], answer: 0, explanation: "Properties set by the count of solute particles (freezing-point depression, boiling-point elevation, osmotic pressure) are colligative.", difficulty: "easy", source: "original" },

  { id: "gs3-gc-039", subject: "general_chemistry", topic: "acids_bases", stimulusId: "gs3-c10", stimulus: { kind: "html", content: ST28, attribution: "Original" }, stem: "When [A-] = [HA], the buffer pH is:", format: "single_best", options: ["3.74", "5.74", "7.00", "4.74"], answer: 3, explanation: "If the ratio is 1, log(1) = 0, so pH = pKa = 4.74.", difficulty: "easy", source: "original" },
  { id: "gs3-gc-040", subject: "general_chemistry", topic: "acids_bases", stimulusId: "gs3-c10", stimulus: { kind: "html", content: ST28, attribution: "Original" }, stem: "A buffer with ten times as much A- as HA has pH:", format: "single_best", options: ["3.74", "5.74", "4.74", "14.74"], answer: 1, explanation: "log(10) = 1, so pH = 4.74 + 1 = 5.74, as the table shows.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-041", subject: "general_chemistry", topic: "acids_bases", stimulusId: "gs3-c10", stimulus: { kind: "html", content: ST28, attribution: "Original" }, stem: "Adding a small amount of strong acid to this buffer changes the pH only slightly because the added H+ is mostly:", format: "single_best", options: ["absorbed by A-, which becomes HA", "converted to water with no other change", "left free in solution", "evaporated"], answer: 0, explanation: "The conjugate base A- mops up added H+ to form HA, so the [A-]/[HA] ratio barely shifts and pH changes little.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-042", subject: "general_chemistry", topic: "acids_bases", stimulusId: "gs3-c10", stimulus: { kind: "html", content: ST28, attribution: "Original" }, stem: "This buffer is most effective (best at resisting pH change) when the desired pH is closest to:", format: "single_best", options: ["4.74", "1.0", "7.00", "9.0"], answer: 0, explanation: "Buffering is strongest near pH = pKa, where the ratio is about 1 and there is plenty of both HA and A- to absorb added acid or base.", difficulty: "medium", source: "original" },

  { id: "gs3-gc-043", subject: "general_chemistry", topic: "gases", stimulusId: "gs3-c11", stimulus: { kind: "html", content: ST29, attribution: "Original" }, stem: "The gas is heated to 600 K at constant volume. The new pressure is:", format: "single_best", options: ["100 kPa", "200 kPa", "50 kPa", "150 kPa"], answer: 1, explanation: "At constant V, P is proportional to T. Doubling T from 300 to 600 K doubles P to 200 kPa.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-044", subject: "general_chemistry", topic: "gases", stimulusId: "gs3-c11", stimulus: { kind: "html", content: ST29, attribution: "Original" }, stem: "Instead the gas is compressed to 1.0 L at constant temperature (300 K). The new pressure is:", format: "single_best", options: ["50 kPa", "100 kPa", "200 kPa", "400 kPa"], answer: 2, explanation: "At constant T, PV is constant (Boyle's law). Halving V from 2.0 to 1.0 L doubles P to 200 kPa.", difficulty: "medium", source: "original" },
  { id: "gs3-gc-045", subject: "general_chemistry", topic: "gases", stimulusId: "gs3-c11", stimulus: { kind: "html", content: ST29, attribution: "Original" }, stem: "A student uses 27 in the gas law instead of converting to kelvin. The error is that temperature must be measured:", format: "single_best", options: ["in degrees Celsius", "in fahrenheit", "on the absolute (kelvin) scale, where doubling really doubles the energy", "as a percentage"], answer: 2, explanation: "Gas-law ratios require absolute temperature; 27 degrees C is 300 K, and only the kelvin value makes doubling temperature meaningful.", difficulty: "easy", source: "original" },
  { id: "gs3-gc-046", subject: "general_chemistry", topic: "gases", stimulusId: "gs3-c11", stimulus: { kind: "html", content: ST29, attribution: "Original" }, stem: "If the absolute temperature is doubled (to 600 K) and the volume is halved (to 1.0 L) together, the pressure becomes:", format: "single_best", options: ["100 kPa", "200 kPa", "400 kPa", "50 kPa"], answer: 2, explanation: "P = (n R T)/V, so P scales with T and inversely with V: doubling T and halving V multiplies P by 4, giving 400 kPa.", difficulty: "hard", source: "original" },

  { id: "gs3-oc-001", subject: "organic_chemistry", topic: "spectroscopy", stimulusId: "gs3-o1", stimulus: { kind: "html", content: ST30, attribution: "Original" }, stem: "The strong 1715 cm^-1 band tells you the molecule contains:", format: "single_best", options: ["a carbon-carbon double bond", "an O-H group", "a carbonyl (C=O) group", "only single bonds"], answer: 2, explanation: "An absorption near 1700 to 1750 cm-1 is the hallmark of a carbonyl (C=O) stretch.", difficulty: "easy", source: "original" },
  { id: "gs3-oc-002", subject: "organic_chemistry", topic: "spectroscopy", stimulusId: "gs3-o1", stimulus: { kind: "html", content: ST30, attribution: "Original" }, stem: "The absence of a broad band above 3000 cm^-1 rules out:", format: "single_best", options: ["a C=O group", "an O-H group (so it is not a carboxylic acid or alcohol)", "any carbon atoms", "the molecule being organic"], answer: 1, explanation: "A broad high-wavenumber band signals O-H. Its absence means no alcohol or carboxylic acid O-H, so the carbonyl belongs to an aldehyde or ketone.", difficulty: "medium", source: "original" },
  { id: "gs3-oc-003", subject: "organic_chemistry", topic: "spectroscopy", stimulusId: "gs3-o1", stimulus: { kind: "html", content: ST30, attribution: "Original" }, stem: "A single NMR peak integrating to 6 equivalent hydrogens, with C3H6O, points to:", format: "single_best", options: ["propanal, CH3CH2CHO", "propan-1-ol", "prop-2-en-1-ol", "propanone (acetone), CH3COCH3"], answer: 3, explanation: "Acetone has two identical CH3 groups either side of the C=O, giving all 6 H one equivalent environment, hence a single peak. Propanal would show three different signals.", difficulty: "hard", source: "original" },
  { id: "gs3-oc-004", subject: "organic_chemistry", topic: "spectroscopy", stimulusId: "gs3-o1", stimulus: { kind: "html", content: ST30, attribution: "Original" }, stem: "The clearest single piece of evidence that the compound is a ketone rather than an aldehyde is:", format: "single_best", options: ["the C=O band at 1715", "the absence of any peak near 9.7 ppm (no aldehyde C-H)", "the molecular formula", "the absence of O-H"], answer: 1, explanation: "An aldehyde would show a distinctive proton near 9.7 ppm. Its absence (only the 6H peak at 2.1 ppm) confirms a ketone.", difficulty: "hard", source: "original" },
  { id: "gs3-oc-005", subject: "organic_chemistry", topic: "structure_isomerism", stimulusId: "gs3-o1", stimulus: { kind: "html", content: ST30, attribution: "Original" }, stem: "The degree of unsaturation of C3H6O is:", format: "single_best", options: ["0", "2", "1", "3"], answer: 2, explanation: "Degrees of unsaturation = (2 x 3 + 2 - 6)/2 = 1, accounted for by the one C=O double bond (no ring needed).", difficulty: "medium", source: "original" },

  { id: "gs3-oc-006", subject: "organic_chemistry", topic: "reactions_mechanisms", stimulusId: "gs3-o2", stimulus: { kind: "html", content: ST31, attribution: "Original" }, stem: "With a strong nucleophile the rate falls steeply from methyl to tertiary. This trend is characteristic of:", format: "single_best", options: ["an SN1 mechanism", "an SN2 mechanism, hindered by bulky groups", "no reaction", "radical substitution"], answer: 1, explanation: "SN2 needs the nucleophile to attack the carbon directly; bulky tertiary groups block this back-side approach, so the rate drops as substitution increases.", difficulty: "hard", source: "original" },
  { id: "gs3-oc-007", subject: "organic_chemistry", topic: "reactions_mechanisms", stimulusId: "gs3-o2", stimulus: { kind: "html", content: ST31, attribution: "Original" }, stem: "An SN2 reaction at a chiral carbon proceeds with:", format: "single_best", options: ["inversion of configuration (like an umbrella in the wind)", "retention of configuration", "no stereochemical change", "loss of all the hydrogens"], answer: 0, explanation: "The nucleophile attacks opposite the leaving group, flipping the three other groups through to the far side: inversion of configuration.", difficulty: "medium", source: "original" },
  { id: "gs3-oc-008", subject: "organic_chemistry", topic: "reactions_mechanisms", stimulusId: "gs3-o2", stimulus: { kind: "html", content: ST31, attribution: "Original" }, stem: "An SN2 rate depends on the concentrations of both the substrate and the nucleophile. The rate law is therefore:", format: "single_best", options: ["rate = k[substrate] only", "rate = k[nucleophile] only", "rate = k[substrate][nucleophile]", "rate = k (a constant)"], answer: 2, explanation: "SN2 is bimolecular: its single concerted step involves both species, so rate = k[substrate][nucleophile], first order in each.", difficulty: "medium", source: "original" },
  { id: "gs3-oc-009", subject: "organic_chemistry", topic: "reactions_mechanisms", stimulusId: "gs3-o2", stimulus: { kind: "html", content: ST31, attribution: "Original" }, stem: "Under these new conditions the tertiary substrate is fastest because it:", format: "single_best", options: ["is the least hindered", "forms the most stable carbocation, favouring an SN1 pathway", "has the most hydrogens", "cannot ionise"], answer: 1, explanation: "Weak nucleophile and ionising solvent favour SN1, whose slow step is forming a carbocation. The tertiary carbocation is the most stable, so the tertiary substrate now reacts fastest.", addedInfo: "The experiment is repeated with a weak nucleophile in a polar protic solvent (water). Now the tertiary substrate reacts fastest and the methyl one barely reacts.", difficulty: "hard", source: "original" },
  { id: "gs3-oc-010", subject: "organic_chemistry", topic: "reactions_mechanisms", stimulusId: "gs3-o2", stimulus: { kind: "html", content: ST31, attribution: "Original" }, stem: "A key signature of the SN1 mechanism is that its rate is:", format: "single_best", options: ["independent of the nucleophile concentration", "proportional to the nucleophile concentration squared", "zero", "fastest for methyl substrates"], answer: 0, explanation: "In SN1 the slow, rate-determining step is ionisation of the substrate; the nucleophile joins only afterwards, so its concentration does not affect the rate.", difficulty: "hard", source: "original" },

  { id: "gs3-oc-011", subject: "organic_chemistry", topic: "acidity_basicity", stimulusId: "gs3-o3", stimulus: { kind: "html", content: ST32, attribution: "Original" }, stem: "The strongest acid in the table is:", format: "single_best", options: ["trichloroacetic acid", "ethanol", "phenol", "acetic acid"], answer: 0, explanation: "The strongest acid has the smallest pKa. Trichloroacetic acid at 0.7 is far stronger than the others.", difficulty: "easy", source: "original" },
  { id: "gs3-oc-012", subject: "organic_chemistry", topic: "acidity_basicity", stimulusId: "gs3-o3", stimulus: { kind: "html", content: ST32, attribution: "Original" }, stem: "Trichloroacetic acid (pKa 0.7) is far stronger than acetic acid (pKa 4.8) because the three chlorine atoms:", format: "single_best", options: ["withdraw electron density, stabilising the negative conjugate base", "donate electrons to the carbon", "add mass to the molecule", "form hydrogen bonds"], answer: 0, explanation: "Electronegative Cl atoms pull electron density away, spreading out and stabilising the negative charge of the carboxylate conjugate base, which makes losing the proton easier.", difficulty: "hard", source: "original" },
  { id: "gs3-oc-013", subject: "organic_chemistry", topic: "acidity_basicity", stimulusId: "gs3-o3", stimulus: { kind: "html", content: ST32, attribution: "Original" }, stem: "Phenol (pKa 10) is much more acidic than ethanol (pKa 16) because the phenoxide ion is:", format: "single_best", options: ["stabilised by resonance delocalisation into the ring", "a stronger base", "less stable than ethoxide", "non-polar"], answer: 0, explanation: "The negative charge of phenoxide is spread over the aromatic ring by resonance, stabilising it. Ethoxide has no such delocalisation, so ethanol holds its proton more tightly.", difficulty: "hard", source: "original" },
  { id: "gs3-oc-014", subject: "organic_chemistry", topic: "acidity_basicity", stimulusId: "gs3-o3", stimulus: { kind: "html", content: ST32, attribution: "Original" }, stem: "Which conjugate base is the WEAKEST base?", format: "single_best", options: ["ethoxide (from ethanol)", "phenoxide (from phenol)", "acetate (from acetic acid)", "trichloroacetate (from trichloroacetic acid)"], answer: 3, explanation: "The strongest acid has the weakest conjugate base. Trichloroacetic acid is strongest, so trichloroacetate is the weakest (most stable, least reactive) base.", difficulty: "medium", source: "original" },

  { id: "gs3-oc-015", subject: "organic_chemistry", topic: "structure_isomerism", stimulusId: "gs3-o4", stimulus: { kind: "html", content: ST33, attribution: "Original" }, stem: "How many structural isomers does C5H12 have?", format: "single_best", options: ["2", "5", "4", "3"], answer: 3, explanation: "The table lists 3 (pentane, 2-methylbutane and 2,2-dimethylpropane).", difficulty: "easy", source: "original" },
  { id: "gs3-oc-016", subject: "organic_chemistry", topic: "structure_isomerism", stimulusId: "gs3-o4", stimulus: { kind: "html", content: ST33, attribution: "Original" }, stem: "Which molecule contains a chiral carbon (four different groups on one carbon)?", format: "single_best", options: ["2-bromobutane, CH3CHBrCH2CH3", "2-bromopropane, (CH3)2CHBr", "bromoethane, CH3CH2Br", "2-bromo-2-methylpropane"], answer: 0, explanation: "In 2-bromobutane the second carbon carries H, Br, a methyl and an ethyl group: four different groups, so it is a chiral centre. The others each have at least two identical groups on the key carbon.", difficulty: "hard", source: "original" },
  { id: "gs3-oc-017", subject: "organic_chemistry", topic: "structure_isomerism", stimulusId: "gs3-o4", stimulus: { kind: "html", content: ST33, attribution: "Original" }, stem: "Which compound shows cis/trans (geometric) isomerism?", format: "single_best", options: ["but-1-ene, CH2=CHCH2CH3", "butane", "but-2-ene, CH3CH=CHCH3", "2-methylpropane"], answer: 2, explanation: "But-2-ene has each double-bonded carbon carrying a different pair (H and CH3), so cis and trans forms exist. But-1-ene's terminal =CH2 has two identical H, so it cannot.", difficulty: "hard", source: "original" },
  { id: "gs3-oc-018", subject: "organic_chemistry", topic: "structure_isomerism", stimulusId: "gs3-o4", stimulus: { kind: "html", content: ST33, attribution: "Original" }, stem: "The data show the number of isomers rising 2, 3, 5 as carbons increase. This illustrates that:", format: "single_best", options: ["isomer count falls with chain length", "all alkanes have the same number of isomers", "isomers do not exist beyond C4", "the number of possible structures grows rapidly with more carbon atoms"], answer: 3, explanation: "More carbons allow more branching arrangements, so the number of structural isomers climbs quickly with chain length.", difficulty: "easy", source: "original" },

  { id: "gs3-oc-019", subject: "organic_chemistry", topic: "reactions_mechanisms", stimulusId: "gs3-o5", stimulus: { kind: "html", content: ST34, attribution: "Original" }, stem: "Mild oxidation of a primary alcohol first gives:", format: "single_best", options: ["a ketone", "an aldehyde", "a carboxylic acid", "carbon dioxide"], answer: 1, explanation: "Following the ladder, a primary alcohol (-CH2OH) is oxidised first to an aldehyde (-CHO), then on to a carboxylic acid with stronger oxidation.", difficulty: "medium", source: "original" },
  { id: "gs3-oc-020", subject: "organic_chemistry", topic: "reactions_mechanisms", stimulusId: "gs3-o5", stimulus: { kind: "html", content: ST34, attribution: "Original" }, stem: "Oxidising a secondary alcohol such as propan-2-ol gives:", format: "single_best", options: ["an aldehyde", "a carboxylic acid", "no reaction", "a ketone"], answer: 3, explanation: "A secondary alcohol oxidises to a ketone and stops there, since the carbonyl carbon has no further C-H to lose toward an acid.", difficulty: "medium", source: "original" },
  { id: "gs3-oc-021", subject: "organic_chemistry", topic: "reactions_mechanisms", stimulusId: "gs3-o5", stimulus: { kind: "html", content: ST34, attribution: "Original" }, stem: "A tertiary alcohol resists oxidation because the carbon bearing the -OH:", format: "single_best", options: ["is negatively charged", "is aromatic", "has no hydrogen atom to remove", "already has a C=O"], answer: 2, explanation: "Oxidation here removes a hydrogen from the carbon holding the -OH. A tertiary carbon has no such hydrogen, so it cannot be oxidised this way.", difficulty: "medium", source: "original" },
  { id: "gs3-oc-022", subject: "organic_chemistry", topic: "reactions_mechanisms", stimulusId: "gs3-o5", stimulus: { kind: "html", content: ST34, attribution: "Original" }, stem: "Converting a carboxylic acid back to a primary alcohol is classified as:", format: "single_best", options: ["an oxidation", "a substitution", "a neutralisation", "a reduction"], answer: 3, explanation: "Moving left along the oxidation ladder (acid to alcohol) means removing bonds to oxygen, which is a reduction.", difficulty: "medium", source: "original" },

  { id: "gs3-oc-023", subject: "organic_chemistry", topic: "biomolecules", stimulusId: "gs3-o6", stimulus: { kind: "html", content: ST35, attribution: "Original" }, stem: "At pH 1 (strongly acidic), the amino acid carries a net charge of:", format: "single_best", options: ["0", "-1", "-2", "+1"], answer: 3, explanation: "At low pH both groups are protonated: -COOH (neutral) and -NH3+ (positive), giving a net charge of +1.", difficulty: "medium", source: "original" },
  { id: "gs3-oc-024", subject: "organic_chemistry", topic: "biomolecules", stimulusId: "gs3-o6", stimulus: { kind: "html", content: ST35, attribution: "Original" }, stem: "In electrophoresis at pH 12, the amino acid will move toward the:", format: "single_best", options: ["negative electrode (cathode)", "neither electrode", "both electrodes", "positive electrode (anode), because it is negatively charged"], answer: 3, explanation: "At pH 12 the net charge is -1, so the molecule migrates toward the oppositely charged positive electrode.", difficulty: "hard", source: "original" },
  { id: "gs3-oc-025", subject: "organic_chemistry", topic: "biomolecules", stimulusId: "gs3-o6", stimulus: { kind: "html", content: ST35, attribution: "Original" }, stem: "At its isoelectric point (pI), the amino acid:", format: "single_best", options: ["does not move in an electric field, as its net charge is zero", "carries a large positive charge", "is most soluble", "is fully protonated"], answer: 0, explanation: "At the pI the positive and negative charges balance to zero net charge, so the molecule does not migrate in electrophoresis.", difficulty: "medium", source: "original" },
  { id: "gs3-oc-026", subject: "organic_chemistry", topic: "biomolecules", stimulusId: "gs3-o6", stimulus: { kind: "html", content: ST35, attribution: "Original" }, stem: "Compared with a simple amino acid (pI about 6), aspartic acid would have a pI that is:", format: "single_best", options: ["lower (more acidic)", "higher (more basic)", "exactly 6", "exactly 12"], answer: 0, explanation: "An extra acidic group adds negative charge, so a lower pH is needed to reach zero net charge: the pI shifts lower (acidic amino acids have pI around 3).", addedInfo: "Aspartic acid has an extra acidic -COOH side chain.", difficulty: "hard", source: "original" },

  { id: "gs3-oc-027", subject: "organic_chemistry", topic: "structure_isomerism", stimulusId: "gs3-o7", stimulus: { kind: "html", content: ST36, attribution: "Original" }, stem: "Acetic acid has the highest boiling point of the four despite a similar molar mass because it has:", format: "single_best", options: ["the strongest hydrogen bonding (it even pairs into dimers)", "the weakest dispersion forces", "the smallest molecules", "no intermolecular forces"], answer: 0, explanation: "The -COOH group forms strong hydrogen bonds (carboxylic acids even dimerise), so more energy is needed to separate the molecules, giving the highest boiling point.", difficulty: "medium", source: "original" },
  { id: "gs3-oc-028", subject: "organic_chemistry", topic: "structure_isomerism", stimulusId: "gs3-o7", stimulus: { kind: "html", content: ST36, attribution: "Original" }, stem: "Butane has by far the lowest boiling point because its molecules are held together only by:", format: "single_best", options: ["hydrogen bonds", "ionic bonds", "dipole-dipole forces", "weak dispersion (van der Waals) forces"], answer: 3, explanation: "Butane is non-polar, so only weak induced-dipole (dispersion) forces act between molecules, giving the lowest boiling point.", difficulty: "easy", source: "original" },
  { id: "gs3-oc-029", subject: "organic_chemistry", topic: "structure_isomerism", stimulusId: "gs3-o7", stimulus: { kind: "html", content: ST36, attribution: "Original" }, stem: "Propanal boils higher than butane but lower than propan-1-ol. This is because propanal has:", format: "single_best", options: ["hydrogen bonding stronger than the alcohol", "no polarity at all", "ionic character", "dipole-dipole forces (from its C=O) but no O-H to hydrogen bond"], answer: 3, explanation: "Propanal's polar C=O gives dipole-dipole attraction (stronger than butane's dispersion) but it lacks the O-H needed for hydrogen bonding, so it boils below the alcohol.", difficulty: "hard", source: "original" },
  { id: "gs3-oc-030", subject: "organic_chemistry", topic: "structure_isomerism", stimulusId: "gs3-o7", stimulus: { kind: "html", content: ST36, attribution: "Original" }, stem: "Branching lowers the boiling point because a more compact, branched molecule has:", format: "single_best", options: ["stronger hydrogen bonds", "less surface area for dispersion forces between molecules", "a larger surface area for contact", "a higher molar mass"], answer: 1, explanation: "Branched molecules are more spherical, touching neighbours over less surface, which weakens the total dispersion forces and lowers the boiling point.", addedInfo: "Among the three isomers of C5H12, the straight chain pentane boils at 36°C while the most branched, 2,2-dimethylpropane, boils at 9°C.", difficulty: "hard", source: "original" },

  { id: "gs3-oc-031", subject: "organic_chemistry", topic: "reactions_mechanisms", stimulusId: "gs3-o8", stimulus: { kind: "html", content: ST37, attribution: "Original" }, stem: "The major product of HBr adding to propene is:", format: "single_best", options: ["1-bromopropane (Br on the end carbon)", "propan-2-ol", "2-bromopropane (Br on the middle carbon)", "1,2-dibromopropane"], answer: 2, explanation: "By Markovnikov's rule, H adds to the CH2 end (more hydrogens) and Br to the middle carbon, giving 2-bromopropane as the major product.", difficulty: "medium", source: "original" },
  { id: "gs3-oc-032", subject: "organic_chemistry", topic: "reactions_mechanisms", stimulusId: "gs3-o8", stimulus: { kind: "html", content: ST37, attribution: "Original" }, stem: "The Markovnikov outcome is explained by the reaction passing through the more stable:", format: "single_best", options: ["secondary carbocation", "primary carbocation", "bromide ion", "alkane"], answer: 0, explanation: "Adding H+ to the terminal carbon leaves a positive charge on the middle (secondary) carbon. The secondary carbocation is more stable than the primary alternative, so it dominates.", difficulty: "hard", source: "original" },
  { id: "gs3-oc-033", subject: "organic_chemistry", topic: "reactions_mechanisms", stimulusId: "gs3-o8", stimulus: { kind: "html", content: ST37, attribution: "Original" }, stem: "Shaking an unknown liquid with orange bromine water decolourises it quickly. This indicates the liquid:", format: "single_best", options: ["is a saturated alkane", "contains a C=C double bond that adds bromine", "is an acid", "is water"], answer: 1, explanation: "Bromine adds across a C=C double bond, removing the orange colour. Rapid decolourisation of bromine water is the classic test for unsaturation (an alkene).", difficulty: "medium", source: "original" },
  { id: "gs3-oc-034", subject: "organic_chemistry", topic: "reactions_mechanisms", stimulusId: "gs3-o8", stimulus: { kind: "html", content: ST37, attribution: "Original" }, stem: "Reacting propene with hydrogen gas over a nickel catalyst (H2/Ni) gives propane. This addition of hydrogen is:", format: "single_best", options: ["a reduction (hydrogenation)", "an oxidation", "a substitution", "a polymerisation"], answer: 0, explanation: "Adding H2 across the double bond removes unsaturation and adds hydrogen: a reduction, specifically catalytic hydrogenation.", difficulty: "medium", source: "original" },

  { id: "gs3-ph-001", subject: "physics", topic: "kinematics", stimulusId: "gs3-p1", stimulus: { kind: "html", content: ST38, attribution: "Original" }, stem: "The acceleration of the trolley is:", format: "single_best", options: ["2 m/s^2", "10 m/s^2", "5 m/s^2", "30 m/s^2"], answer: 2, explanation: "Acceleration is the slope of the velocity-time line: every 2 s the velocity rises 10 m/s, so a = 10/2 = 5 m/s^2.", difficulty: "easy", source: "original" },
  { id: "gs3-ph-002", subject: "physics", topic: "kinematics", stimulusId: "gs3-p1", stimulus: { kind: "html", content: ST38, attribution: "Original" }, stem: "The distance travelled in the first 6 s equals the area under the line, which is:", format: "single_best", options: ["180 m", "90 m", "60 m", "30 m"], answer: 1, explanation: "Area of the triangle = (1/2) x base x height = (1/2) x 6 s x 30 m/s = 90 m.", difficulty: "medium", source: "original" },
  { id: "gs3-ph-003", subject: "physics", topic: "kinematics", stimulusId: "gs3-p1", stimulus: { kind: "html", content: ST38, attribution: "Original" }, stem: "For uniform acceleration from rest, distance is proportional to (time)^2. In the first 12 s the trolley would travel:", format: "single_best", options: ["360 m", "180 m", "270 m", "90 m"], answer: 0, explanation: "Distance scales with t^2. Doubling the time from 6 to 12 s multiplies the distance by 4: 90 x 4 = 360 m.", difficulty: "hard", source: "original" },
  { id: "gs3-ph-004", subject: "physics", topic: "kinematics", stimulusId: "gs3-p1", stimulus: { kind: "html", content: ST38, attribution: "Original" }, stem: "The extra distance it covers between 6 s and 10 s is:", format: "single_best", options: ["30 m", "120 m", "60 m", "300 m"], answer: 1, explanation: "At constant velocity, distance = speed x time = 30 m/s x 4 s = 120 m.", addedInfo: "At t = 6 s the acceleration stops and the trolley continues at a steady 30 m/s.", difficulty: "medium", source: "original" },

  { id: "gs3-ph-005", subject: "physics", topic: "forces_energy", stimulusId: "gs3-p2", stimulus: { kind: "html", content: ST39, attribution: "Original" }, stem: "The weight of the 2 kg block is:", format: "single_best", options: ["2 N", "10 N", "20 N", "200 N"], answer: 2, explanation: "Weight = mg = 2 x 10 = 20 N.", difficulty: "easy", source: "original" },
  { id: "gs3-ph-006", subject: "physics", topic: "forces_energy", stimulusId: "gs3-p2", stimulus: { kind: "html", content: ST39, attribution: "Original" }, stem: "If a net horizontal force of 10 N acts on the block, its acceleration is:", format: "single_best", options: ["20 m/s^2", "0.2 m/s^2", "12 m/s^2", "5 m/s^2"], answer: 3, explanation: "a = F/m = 10 N / 2 kg = 5 m/s^2.", difficulty: "easy", source: "original" },
  { id: "gs3-ph-007", subject: "physics", topic: "forces_energy", stimulusId: "gs3-p2", stimulus: { kind: "html", content: ST39, attribution: "Original" }, stem: "Released on a frictionless 30° slope, the block accelerates down it at:", format: "single_best", options: ["10 m/s^2", "20 m/s^2", "5 m/s^2", "2.5 m/s^2"], answer: 2, explanation: "Force along the slope = mg sin30 = 20 x 0.5 = 10 N; a = F/m = 10/2 = 5 m/s^2.", difficulty: "hard", source: "original" },
  { id: "gs3-ph-008", subject: "physics", topic: "forces_energy", stimulusId: "gs3-p2", stimulus: { kind: "html", content: ST39, attribution: "Original" }, stem: "The block's acceleration down the 30° slope becomes:", format: "single_best", options: ["5 m/s^2", "7 m/s^2", "2 m/s^2", "3 m/s^2"], answer: 3, explanation: "Net force = 10 N (gravity component) - 4 N (friction) = 6 N; a = 6/2 = 3 m/s^2.", addedInfo: "A constant friction force of 4 N now acts up the slope, opposing the motion.", difficulty: "hard", source: "original" },

  { id: "gs3-ph-009", subject: "physics", topic: "electricity", stimulusId: "gs3-p3", stimulus: { kind: "html", content: ST40, attribution: "Original" }, stem: "In the series arrangement (6 ohm total), the current drawn from the battery is:", format: "single_best", options: ["6 A", "2 A", "0.5 A", "72 A"], answer: 1, explanation: "I = V/R = 12 V / 6 ohm = 2 A.", difficulty: "easy", source: "original" },
  { id: "gs3-ph-010", subject: "physics", topic: "electricity", stimulusId: "gs3-p3", stimulus: { kind: "html", content: ST40, attribution: "Original" }, stem: "In the parallel arrangement (1.33 ohm total), the current drawn from the battery is closest to:", format: "single_best", options: ["9 A", "2 A", "6 A", "16 A"], answer: 0, explanation: "I = V/R = 12 / 1.33 = 9 A. Parallel resistors give a lower total resistance, so more current flows.", difficulty: "medium", source: "original" },
  { id: "gs3-ph-011", subject: "physics", topic: "electricity", stimulusId: "gs3-p3", stimulus: { kind: "html", content: ST40, attribution: "Original" }, stem: "Comparing the two circuits, the parallel arrangement draws more current because it has:", format: "single_best", options: ["a lower total resistance", "a higher total resistance", "more voltage", "fewer electrons"], answer: 0, explanation: "Parallel paths reduce total resistance (1.33 ohm versus 6 ohm). For the same 12 V, lower resistance means greater current.", difficulty: "medium", source: "original" },
  { id: "gs3-ph-012", subject: "physics", topic: "electricity", stimulusId: "gs3-p3", stimulus: { kind: "html", content: ST40, attribution: "Original" }, stem: "The total power delivered by the battery in the series circuit is:", format: "single_best", options: ["6 W", "24 W", "12 W", "48 W"], answer: 1, explanation: "P = VI = 12 V x 2 A = 24 W.", difficulty: "medium", source: "original" },
  { id: "gs3-ph-013", subject: "physics", topic: "electricity", stimulusId: "gs3-p3", stimulus: { kind: "html", content: ST40, attribution: "Original" }, stem: "The current now flowing is:", format: "single_best", options: ["unchanged at 2 A", "doubled", "halved", "zero, because the single path is broken"], answer: 3, explanation: "A series circuit has only one path. Breaking it anywhere stops the current everywhere, so it falls to zero.", addedInfo: "In the series circuit, one of the two resistors burns out and becomes a break (an open circuit).", difficulty: "medium", source: "original" },

  { id: "gs3-ph-014", subject: "physics", topic: "nuclear", stimulusId: "gs3-p4", stimulus: { kind: "html", content: ST41, attribution: "Original" }, stem: "The half-life of the sample is:", format: "single_best", options: ["5 days", "2.5 days", "10 days", "15 days"], answer: 0, explanation: "The activity halves (800 to 400 to 200 to 100) every 5 days, so the half-life is 5 days.", difficulty: "easy", source: "original" },
  { id: "gs3-ph-015", subject: "physics", topic: "nuclear", stimulusId: "gs3-p4", stimulus: { kind: "html", content: ST41, attribution: "Original" }, stem: "The activity at 20 days will be:", format: "single_best", options: ["0 Bq", "25 Bq", "75 Bq", "50 Bq"], answer: 3, explanation: "Continuing to halve every 5 days: 100 at 15 days becomes 50 Bq at 20 days.", difficulty: "medium", source: "original" },
  { id: "gs3-ph-016", subject: "physics", topic: "nuclear", stimulusId: "gs3-p4", stimulus: { kind: "html", content: ST41, attribution: "Original" }, stem: "After exactly 3 half-lives, the fraction of the original radioactive nuclei remaining is:", format: "single_best", options: ["1/3", "1/6", "1/8", "1/9"], answer: 2, explanation: "Each half-life leaves one half: after 3 it is (1/2)^3 = 1/8.", difficulty: "medium", source: "original" },
  { id: "gs3-ph-017", subject: "physics", topic: "nuclear", stimulusId: "gs3-p4", stimulus: { kind: "html", content: ST41, attribution: "Original" }, stem: "Each alpha emission changes the parent nucleus by:", format: "single_best", options: ["increasing the atomic number by 1", "decreasing the mass number by 4 and the atomic number by 2", "decreasing the mass number by 2 only", "leaving both numbers unchanged"], answer: 1, explanation: "Losing a helium nucleus removes 2 protons and 2 neutrons, so the mass number drops by 4 and the atomic number by 2.", addedInfo: "This nuclide decays by emitting an alpha particle (a helium nucleus, 2 protons and 2 neutrons).", difficulty: "medium", source: "original" },

  { id: "gs3-ph-018", subject: "physics", topic: "waves_sound", stimulusId: "gs3-p5", stimulus: { kind: "html", content: ST42, attribution: "Original" }, stem: "A sound wave of wavelength 2 m travels at 340 m/s. Its frequency is:", format: "single_best", options: ["680 Hz", "170 Hz", "342 Hz", "85 Hz"], answer: 1, explanation: "f = v/lambda = 340 / 2 = 170 Hz.", difficulty: "easy", source: "original" },
  { id: "gs3-ph-019", subject: "physics", topic: "waves_sound", stimulusId: "gs3-p5", stimulus: { kind: "html", content: ST42, attribution: "Original" }, stem: "A string of length 1 m is fixed at both ends. Its fundamental wavelength is:", format: "single_best", options: ["0.5 m", "1 m", "4 m", "2 m"], answer: 3, explanation: "The fundamental wavelength is twice the length: 2L = 2 x 1 = 2 m.", difficulty: "medium", source: "original" },
  { id: "gs3-ph-020", subject: "physics", topic: "waves_sound", stimulusId: "gs3-p5", stimulus: { kind: "html", content: ST42, attribution: "Original" }, stem: "If waves travel at 100 m/s on that 1 m string (fundamental wavelength 2 m), the third harmonic frequency is:", format: "single_best", options: ["50 Hz", "100 Hz", "150 Hz", "300 Hz"], answer: 2, explanation: "Fundamental f1 = v/lambda = 100/2 = 50 Hz. The third harmonic is 3 x f1 = 150 Hz.", difficulty: "hard", source: "original" },
  { id: "gs3-ph-021", subject: "physics", topic: "waves_sound", stimulusId: "gs3-p5", stimulus: { kind: "html", content: ST42, attribution: "Original" }, stem: "When a sound wave passes from air into water, where it travels much faster, its frequency stays the same. Therefore its wavelength:", format: "single_best", options: ["decreases", "stays the same", "increases", "falls to zero"], answer: 2, explanation: "Frequency is fixed by the source. Since v = f x lambda and v increases, the wavelength must increase in proportion.", difficulty: "hard", source: "original" },

  { id: "gs3-ph-022", subject: "physics", topic: "optics", stimulusId: "gs3-p6", stimulus: { kind: "html", content: ST43, attribution: "Original" }, stem: "An object is placed 20 cm in front of the f = 10 cm converging lens. The image forms at:", format: "single_best", options: ["10 cm", "6.7 cm", "20 cm", "30 cm"], answer: 2, explanation: "1/v = 1/f - 1/u = 1/10 - 1/20 = 1/20, so v = 20 cm (a real image on the far side).", difficulty: "hard", source: "original" },
  { id: "gs3-ph-023", subject: "physics", topic: "optics", stimulusId: "gs3-p6", stimulus: { kind: "html", content: ST43, attribution: "Original" }, stem: "For that object at 20 cm (image at 20 cm), the magnification is:", format: "single_best", options: ["1 (same size)", "0.5 (smaller)", "2 (larger)", "4 (larger)"], answer: 0, explanation: "Magnification = v/u = 20/20 = 1, so the image is the same size as the object (and inverted).", difficulty: "medium", source: "original" },
  { id: "gs3-ph-024", subject: "physics", topic: "optics", stimulusId: "gs3-p6", stimulus: { kind: "html", content: ST43, attribution: "Original" }, stem: "Total internal reflection of light can occur when light travels from:", format: "single_best", options: ["air into glass at any angle", "glass into air, beyond the critical angle", "air into a vacuum", "any medium, at any angle"], answer: 1, explanation: "Total internal reflection needs light moving into a less dense medium (glass to air) at an angle larger than the critical angle.", difficulty: "medium", source: "original" },
  { id: "gs3-ph-025", subject: "physics", topic: "optics", stimulusId: "gs3-p6", stimulus: { kind: "html", content: ST43, attribution: "Original" }, stem: "If the object is placed exactly at the focal point (u = 10 cm), the refracted rays emerge:", format: "single_best", options: ["converging to a point 10 cm away", "back toward the object", "parallel, so the image is at infinity", "at the centre of the lens"], answer: 2, explanation: "1/v = 1/10 - 1/10 = 0, so v is infinite: the rays leave parallel and no real image forms at a finite distance.", difficulty: "hard", source: "original" },

  { id: "gs3-ph-026", subject: "physics", topic: "fluids", stimulusId: "gs3-p7", stimulus: { kind: "html", content: ST44, attribution: "Original" }, stem: "The gauge pressure at a depth of 10 m in water is:", format: "single_best", options: ["10 kPa", "50 kPa", "100 kPa", "1000 kPa"], answer: 2, explanation: "P = rho g h = 1000 x 10 x 10 = 100 000 Pa = 100 kPa, as the table shows.", difficulty: "easy", source: "original" },
  { id: "gs3-ph-027", subject: "physics", topic: "fluids", stimulusId: "gs3-p7", stimulus: { kind: "html", content: ST44, attribution: "Original" }, stem: "Doubling the depth from 5 m to 10 m changes the water pressure from 50 to 100 kPa. Pressure is therefore:", format: "single_best", options: ["independent of depth", "inversely proportional to depth", "directly proportional to depth", "proportional to depth squared"], answer: 2, explanation: "Pressure doubles when depth doubles: P = rho g h is directly proportional to depth.", difficulty: "medium", source: "original" },
  { id: "gs3-ph-028", subject: "physics", topic: "fluids", stimulusId: "gs3-p7", stimulus: { kind: "html", content: ST44, attribution: "Original" }, stem: "A block of density 800 kg/m^3 floats in water (1000 kg/m^3). The fraction of its volume below the surface is:", format: "single_best", options: ["20%", "80%", "100%", "8%"], answer: 1, explanation: "A floating object sinks until it displaces its own weight; the submerged fraction equals the density ratio 800/1000 = 0.8, i.e. 80%.", difficulty: "hard", source: "original" },
  { id: "gs3-ph-029", subject: "physics", topic: "fluids", stimulusId: "gs3-p7", stimulus: { kind: "html", content: ST44, attribution: "Original" }, stem: "The upthrust on a fully submerged object of volume 0.001 m^3 in water is:", format: "single_best", options: ["1 N", "100 N", "10 N", "0.1 N"], answer: 2, explanation: "Upthrust = weight of displaced water = rho g V = 1000 x 10 x 0.001 = 10 N.", difficulty: "medium", source: "original" },

  { id: "gs3-ph-030", subject: "physics", topic: "forces_energy", stimulusId: "gs3-p8", stimulus: { kind: "html", content: ST45, attribution: "Original" }, stem: "The kinetic energy of a 2 kg ball moving at 10 m/s is:", format: "single_best", options: ["20 J", "100 J", "200 J", "10 J"], answer: 1, explanation: "KE = (1/2) m v^2 = 0.5 x 2 x 10^2 = 100 J.", difficulty: "easy", source: "original" },
  { id: "gs3-ph-031", subject: "physics", topic: "forces_energy", stimulusId: "gs3-p8", stimulus: { kind: "html", content: ST45, attribution: "Original" }, stem: "The gravitational potential energy gained by lifting that 2 kg ball 5 m is:", format: "single_best", options: ["10 J", "100 J", "50 J", "1000 J"], answer: 1, explanation: "PE = mgh = 2 x 10 x 5 = 100 J.", difficulty: "easy", source: "original" },
  { id: "gs3-ph-032", subject: "physics", topic: "forces_energy", stimulusId: "gs3-p8", stimulus: { kind: "html", content: ST45, attribution: "Original" }, stem: "A motor consumes 200 J of electrical energy to raise a load, giving it 150 J of potential energy. Its efficiency is:", format: "single_best", options: ["50%", "75%", "133%", "30%"], answer: 1, explanation: "Efficiency = useful out / total in = 150 / 200 = 0.75 = 75%.", difficulty: "medium", source: "original" },
  { id: "gs3-ph-033", subject: "physics", topic: "forces_energy", stimulusId: "gs3-p8", stimulus: { kind: "html", content: ST45, attribution: "Original" }, stem: "If the ball's speed doubles from 10 to 20 m/s, its kinetic energy:", format: "single_best", options: ["quadruples", "doubles", "triples", "stays the same"], answer: 0, explanation: "KE is proportional to v^2, so doubling the speed multiplies the kinetic energy by 4 (from 100 J to 400 J).", difficulty: "medium", source: "original" },

  { id: "gs3-ph-034", subject: "physics", topic: "forces_energy", stimulusId: "gs3-p9", stimulus: { kind: "html", content: ST46, attribution: "Original" }, stem: "The momentum of a 2 kg cart moving at 3 m/s is:", format: "single_best", options: ["1.5 kg m/s", "5 kg m/s", "6 kg m/s", "9 kg m/s"], answer: 2, explanation: "p = mv = 2 x 3 = 6 kg m/s.", difficulty: "easy", source: "original" },
  { id: "gs3-ph-035", subject: "physics", topic: "forces_energy", stimulusId: "gs3-p9", stimulus: { kind: "html", content: ST46, attribution: "Original" }, stem: "That 2 kg cart (3 m/s) collides with and sticks to a stationary 1 kg cart. Their common velocity afterwards is:", format: "single_best", options: ["2 m/s", "1.5 m/s", "3 m/s", "6 m/s"], answer: 0, explanation: "Momentum is conserved: 6 kg m/s is shared by 3 kg total, so v = 6/3 = 2 m/s.", difficulty: "hard", source: "original" },
  { id: "gs3-ph-036", subject: "physics", topic: "forces_energy", stimulusId: "gs3-p9", stimulus: { kind: "html", content: ST46, attribution: "Original" }, stem: "A constant 10 N force acts on a trolley for 2 s. The impulse delivered (and so the change in momentum) is:", format: "single_best", options: ["5 kg m/s", "12 kg m/s", "0.2 kg m/s", "20 kg m/s"], answer: 3, explanation: "Impulse = Ft = 10 N x 2 s = 20 kg m/s, which equals the change in momentum.", difficulty: "medium", source: "original" },
  { id: "gs3-ph-037", subject: "physics", topic: "forces_energy", stimulusId: "gs3-p9", stimulus: { kind: "html", content: ST46, attribution: "Original" }, stem: "In the sticking (inelastic) collision above, the total kinetic energy goes from 9 J before to 6 J after. This shows that in such a collision:", format: "single_best", options: ["kinetic energy is conserved", "momentum is lost", "kinetic energy is not conserved (some becomes heat and deformation), though momentum is", "energy is created"], answer: 2, explanation: "Momentum is always conserved, but in an inelastic collision some kinetic energy converts to heat and deformation, so KE falls from 9 J to 6 J.", difficulty: "hard", source: "original" },

  { id: "gs3-data-001", subject: "maths", topic: "graphs", stimulusId: "gs3-d1", stimulus: { kind: "html", content: ST47, attribution: "Original" }, stem: "Which food provides the most protein per 100 g?", format: "single_best", options: ["almonds", "chicken breast", "rolled oats", "olive oil"], answer: 1, explanation: "Reading the protein column, chicken breast has 31 g, the highest in the table.", difficulty: "easy", source: "original" },
  { id: "gs3-data-002", subject: "maths", topic: "estimation", stimulusId: "gs3-d1", stimulus: { kind: "html", content: ST47, attribution: "Original" }, stem: "By mass, what percentage of almonds is fat?", format: "single_best", options: ["21%", "9%", "12%", "50%"], answer: 3, explanation: "Almonds contain 50 g of fat per 100 g, so fat is 50% of the mass.", difficulty: "medium", source: "original" },
  { id: "gs3-data-003", subject: "maths", topic: "ratios_proportion", stimulusId: "gs3-d1", stimulus: { kind: "html", content: ST47, attribution: "Original" }, stem: "An athlete wants the most protein for the fewest kilojoules (the highest protein-to-energy ratio). The best choice is:", format: "single_best", options: ["almonds", "rolled oats", "chicken breast", "olive oil"], answer: 2, explanation: "Protein per kJ: chicken 31/700 = 0.044, broccoli 3/140 = 0.021, almonds 21/2400 = 0.009, oats 13/1600 = 0.008. Chicken breast is far highest.", difficulty: "hard", source: "original" },
  { id: "gs3-data-004", subject: "maths", topic: "graphs", stimulusId: "gs3-d1", stimulus: { kind: "html", content: ST47, attribution: "Original" }, stem: "Which food's energy comes essentially entirely from fat?", format: "single_best", options: ["rolled oats", "white rice", "olive oil", "broccoli"], answer: 2, explanation: "Olive oil has 100 g fat and 0 g of protein or carbohydrate per 100 g, so all of its 3700 kJ comes from fat.", difficulty: "medium", source: "original" },
  { id: "gs3-data-005", subject: "maths", topic: "ratios_proportion", stimulusId: "gs3-d1", stimulus: { kind: "html", content: ST47, attribution: "Original" }, stem: "This extra fact best explains why, despite a similar mass, almonds (2400 kJ) carry far more energy than oats (1600 kJ): almonds are higher in:", format: "single_best", options: ["fibre", "protein", "water", "fat, the most energy-dense nutrient"], answer: 3, explanation: "Almonds hold 50 g fat versus 7 g in oats. Because fat packs about 37 kJ/g (more than double protein or carbohydrate), that fat dominates the higher energy total.", addedInfo: "Fat supplies about 37 kJ per gram, more than twice the roughly 17 kJ per gram from protein or carbohydrate.", difficulty: "hard", source: "original" },

  { id: "gs3-data-006", subject: "maths", topic: "units", stimulusId: "gs3-d2", stimulus: { kind: "html", content: ST48, attribution: "Original" }, stem: "The total dose the 70 kg patient should receive is:", format: "single_best", options: ["35 mg", "70 mg", "140 mg", "700 mg"], answer: 2, explanation: "Dose = 2 mg/kg x 70 kg = 140 mg.", difficulty: "medium", source: "original" },
  { id: "gs3-data-007", subject: "maths", topic: "units", stimulusId: "gs3-d2", stimulus: { kind: "html", content: ST48, attribution: "Original" }, stem: "Using the 10 mg/mL solution, the volume needed for that dose is:", format: "single_best", options: ["14 mL", "1.4 mL", "140 mL", "0.14 mL"], answer: 0, explanation: "Volume = 140 mg / 10 mg per mL = 14 mL.", difficulty: "medium", source: "original" },
  { id: "gs3-data-008", subject: "maths", topic: "units", stimulusId: "gs3-d2", stimulus: { kind: "html", content: ST48, attribution: "Original" }, stem: "The infusion rate, in mL per minute, is:", format: "single_best", options: ["30 mL/min", "2 mL/min", "0.5 mL/min", "1 mL/min"], answer: 2, explanation: "60 mL over 2 h = 30 mL/h. Dividing by 60 min/h gives 0.5 mL/min.", addedInfo: "The 14 mL dose is diluted to 60 mL and infused steadily over 2 hours.", difficulty: "hard", source: "original" },
  { id: "gs3-data-009", subject: "maths", topic: "units", stimulusId: "gs3-d2", stimulus: { kind: "html", content: ST48, attribution: "Original" }, stem: "A separate trolley moves the patient at 72 km/h between hospitals. In metres per second this is:", format: "single_best", options: ["7.2 m/s", "20 m/s", "200 m/s", "1.2 m/s"], answer: 1, explanation: "72 km/h x 1000 m/km / 3600 s/h = 72000/3600 = 20 m/s.", difficulty: "medium", source: "original" },

  { id: "gs3-data-010", subject: "maths", topic: "logs_powers", stimulusId: "gs3-d3", stimulus: { kind: "html", content: ST49, attribution: "Original" }, stem: "Solution A has pH 3 and solution B has pH 6. The hydrogen-ion concentration in A is greater than in B by a factor of:", format: "single_best", options: ["1000", "3", "30", "100"], answer: 0, explanation: "Each pH unit is a ten-fold change; a difference of 3 units gives 10^3 = 1000 times the [H+].", difficulty: "medium", source: "original" },
  { id: "gs3-data-011", subject: "maths", topic: "logs_powers", stimulusId: "gs3-d3", stimulus: { kind: "html", content: ST49, attribution: "Original" }, stem: "A magnitude-7 earthquake shakes the ground with an amplitude how many times that of a magnitude-5 quake?", format: "single_best", options: ["2", "100", "20", "1000"], answer: 1, explanation: "Each Richter unit is a ten-fold amplitude increase; 2 units give 10^2 = 100 times.", difficulty: "medium", source: "original" },
  { id: "gs3-data-012", subject: "maths", topic: "logs_powers", stimulusId: "gs3-d3", stimulus: { kind: "html", content: ST49, attribution: "Original" }, stem: "Given log10(2) = 0.30, the value of log10(8) is:", format: "single_best", options: ["0.60", "0.90", "2.40", "0.10"], answer: 1, explanation: "8 = 2^3, so log10(8) = 3 x log10(2) = 3 x 0.30 = 0.90.", difficulty: "medium", source: "original" },
  { id: "gs3-data-013", subject: "maths", topic: "logs_powers", stimulusId: "gs3-d3", stimulus: { kind: "html", content: ST49, attribution: "Original" }, stem: "A 60 dB conversation is more intense than a 30 dB whisper by a factor of:", format: "single_best", options: ["2", "30", "1000", "100"], answer: 2, explanation: "The difference is 30 dB. Every 10 dB is a ten-fold intensity rise, so 30 dB = 10^3 = 1000 times.", difficulty: "hard", source: "original" },

  { id: "gs3-data-014", subject: "maths", topic: "ratios_proportion", stimulusId: "gs3-d4", stimulus: { kind: "html", content: ST50, attribution: "Original" }, stem: "If a cell's radius doubles, its surface area increases by a factor of:", format: "single_best", options: ["2", "8", "6", "4"], answer: 3, explanation: "Surface area is proportional to r^2, so doubling r multiplies area by 2^2 = 4.", difficulty: "medium", source: "original" },
  { id: "gs3-data-015", subject: "maths", topic: "ratios_proportion", stimulusId: "gs3-d4", stimulus: { kind: "html", content: ST50, attribution: "Original" }, stem: "If that cell's radius doubles, its volume increases by a factor of:", format: "single_best", options: ["4", "6", "16", "8"], answer: 3, explanation: "Volume is proportional to r^3, so doubling r multiplies volume by 2^3 = 8.", difficulty: "medium", source: "original" },
  { id: "gs3-data-016", subject: "maths", topic: "ratios_proportion", stimulusId: "gs3-d4", stimulus: { kind: "html", content: ST50, attribution: "Original" }, stem: "When the radius doubles, the surface-area-to-volume ratio:", format: "single_best", options: ["halves", "doubles", "quadruples", "stays the same"], answer: 0, explanation: "The ratio scales as 1/r, so doubling r halves it. This is why small cells, with high surface-area-to-volume, exchange materials more efficiently.", difficulty: "hard", source: "original" },
  { id: "gs3-data-017", subject: "maths", topic: "ratios_proportion", stimulusId: "gs3-d4", stimulus: { kind: "html", content: ST50, attribution: "Original" }, stem: "The reaction rate is proportional to 1/√M. If M increases four-fold, the rate becomes:", format: "single_best", options: ["one quarter", "double", "one sixteenth", "one half"], answer: 3, explanation: "Rate scales as 1/sqrt(M); sqrt(4) = 2, so the rate falls to 1/2 of its value.", difficulty: "hard", source: "original" },
];

